import React, { useState, useMemo, useEffect } from 'react';
import { UISettings, ChatSession, Character } from '../types';
import { generateContent } from '../services/geminiService';
import { logger } from '../services/loggingService';
import { SpinnerIcon } from './icons/SpinnerIcon.tsx';
import { UploadIcon } from './icons/UploadIcon.tsx';
import { SparklesIcon } from './icons/SparklesIcon.tsx';
import { TrashIcon } from './icons/TrashIcon.tsx';
import * as themeService from '../services/themeService.ts';
import { InputModal } from './InputModal.tsx';

interface AppearanceModalProps {
  settings: UISettings;
  currentChat: ChatSession | undefined;
  allCharacters: Character[];
  onUpdate: (settings: UISettings) => void;
  onGenerateImage: (prompt: string) => Promise<string | null>;
  onClose: () => void;
}

const ImageControl: React.FC<{
  label: string;
  imageUrl?: string;
  onUpload: (file: File) => void | Promise<void>;
  onGenerate: (type: 'prompt' | 'auto' | 'character') => void;
  onClear: () => void;
  isGenerating: boolean;
  canAutoGenerate: boolean;
  canCharacterGenerate: boolean;
}> = ({ label, imageUrl, onUpload, onGenerate, onClear, isGenerating, canAutoGenerate, canCharacterGenerate }) => {
  const fileInputRef = React.useRef<HTMLInputElement>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 4 * 1024 * 1024) { // 4MB limit
      alert("File is too large. Please select an image under 4MB.");
      return;
    }
    await onUpload(file);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="space-y-3">
      <h3 className="text-lg font-medium text-text-primary">{label}</h3>
      <div className="h-40 w-full rounded-md border-2 border-dashed border-border-strong flex items-center justify-center bg-cover bg-center" style={{ backgroundImage: `url(${imageUrl || ''})`, backgroundColor: imageUrl ? '' : 'rgba(0,0,0,0.1)' }}>
        {!imageUrl && <span className="text-text-secondary">No Image Set</span>}
      </div>
      <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/png, image/jpeg, image/webp, image/gif" className="hidden" />
        <button onClick={() => fileInputRef.current?.click()} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors">
            <UploadIcon className="w-4 h-4" /> <span>Upload</span>
        </button>
        <button onClick={() => onGenerate('prompt')} disabled={isGenerating} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors disabled:opacity-50">
            {isGenerating ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} <span>From Prompt</span>
        </button>
        <button onClick={() => onGenerate('auto')} disabled={isGenerating || !canAutoGenerate} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors disabled:opacity-50" title={!canAutoGenerate ? "Not enough chat history available" : "Generate from chat context"}>
            {isGenerating ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} <span>From Chat</span>
        </button>
        <button onClick={() => onGenerate('character')} disabled={isGenerating || !canCharacterGenerate} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors disabled:opacity-50" title={!canCharacterGenerate ? "No characters in this chat" : "Generate from character details"}>
            {isGenerating ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} <span>From Character</span>
        </button>
        <button onClick={onClear} className="col-span-2 md:col-span-1 flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-accent-red/20 text-accent-red hover:bg-accent-red/30 transition-colors">
            <TrashIcon className="w-4 h-4" /> <span>Clear</span>
        </button>
      </div>
    </div>
  );
};

export const AppearanceModal: React.FC<AppearanceModalProps> = ({ settings, currentChat, allCharacters, onUpdate, onGenerateImage, onClose }) => {
  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [isGeneratingBanner, setIsGeneratingBanner] = useState(false);
  const [activeTheme, setActiveTheme] = useState(themeService.getTheme());
  const [inputModal, setInputModal] = useState<{ title: string, label: string, onConfirm: (val: string) => void } | null>(null);

  useEffect(() => {
    const unsubscribe = themeService.subscribe(() => {
      setActiveTheme(themeService.getTheme());
    });
    return unsubscribe;
  }, []);

  const participants = useMemo(() => {
    if (!currentChat) return [];
    return allCharacters.filter(c => currentChat.characterIds.includes(c.id));
  }, [allCharacters, currentChat]);

  const canAutoGenerate = !!currentChat && currentChat.messages.length >= 2;
  const canCharacterGenerate = participants.length > 0;

  const handleFileUpload = (file: File, type: 'background' | 'banner'): Promise<void> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
          const newSettings = { ...settings };
          if (type === 'background') newSettings.backgroundImage = reader.result as string;
          if (type === 'banner') newSettings.bannerImage = reader.result as string;
          onUpdate(newSettings);
          resolve();
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
  };

  const handleGenerate = async (type: 'background' | 'banner', mode: 'prompt' | 'auto' | 'character') => {
    const setIsGenerating = type === 'background' ? setIsGeneratingBg : setIsGeneratingBanner;

    if (mode === 'prompt') {
        setInputModal({
            title: `Generate ${type === 'background' ? 'Background' : 'Banner'}`,
            label: "Enter an image prompt:",
            onConfirm: async (prompt) => {
                setInputModal(null);
                setIsGenerating(true);
                try {
                    const imageUrl = await onGenerateImage(prompt);
                    if (imageUrl) {
                        const newSettings = { ...settings };
                        if (type === 'background') newSettings.backgroundImage = imageUrl;
                        if (type === 'banner') newSettings.bannerImage = imageUrl;
                        onUpdate(newSettings);
                    }
                } catch (err) {
                    logger.error("Failed to generate image", err);
                    alert(`Could not generate image: ${err instanceof Error ? err.message : String(err)}`);
                } finally {
                    setIsGenerating(false);
                }
            }
        });
        return;
    }

    setIsGenerating(true);
    let promptText: string | null = null;

    try {
        if (mode === 'auto') {
            if (!canAutoGenerate) throw new Error("Not enough chat history to auto-generate an image.");
            const context = currentChat.messages.slice(-5).map(m => m.content).join('\n');
            const summaryPrompt = `Based on the following conversation, create a short, visually descriptive prompt for an atmospheric ${type} image. The prompt should capture the essence of the scene. Be creative and concise. Conversation:\n\n${context}`;
            promptText = await generateContent(summaryPrompt);
            logger.log(`Auto-generated image prompt from chat:`, promptText);
        } else if (mode === 'character') {
            if (!canCharacterGenerate) throw new Error("No characters in this chat to generate an image from.");
            const characterDetails = participants.map(p => {
                let details = `Name: ${p.name}\nDescription: ${p.description}\nPhysical Appearance: ${p.physicalAppearance}\nPersonality: ${p.personalityTraits}`;
                if (p.memory && p.memory !== 'No memories yet.') {
                    details += `\nRecent Memory: ${p.memory}`;
                }
                return details;
            }).join('\n\n---\n\n');

            const summaryPrompt = `Based on the following character details, create a short, visually descriptive prompt for an atmospheric ${type} image that represents them or their environment. Be creative and concise. Character Details:\n\n${characterDetails}`;
            promptText = await generateContent(summaryPrompt);
            logger.log(`Auto-generated image prompt from character details:`, promptText);
        }

        if (promptText) {
            const imageUrl = await onGenerateImage(promptText);
            if (imageUrl) {
                const newSettings = { ...settings };
                if (type === 'background') newSettings.backgroundImage = imageUrl;
                if (type === 'banner') newSettings.bannerImage = imageUrl;
                onUpdate(newSettings);
            }
        }
    } catch (err) {
        const message = err instanceof Error ? err.message : "An unknown error occurred.";
        logger.error("Failed to generate image prompt or image", err);
        alert(`Could not generate image: ${message}`);
    } finally {
        setIsGenerating(false);
    }
  };

  const handleClear = (type: 'background' | 'banner') => {
    const newSettings = { ...settings };
    if (type === 'background') newSettings.backgroundImage = undefined;
    if (type === 'banner') newSettings.bannerImage = undefined;
    onUpdate(newSettings);
  };

  const handleAvatarSizeChange = (size: 'small' | 'medium' | 'large') => {
    onUpdate({ ...settings, avatarSize: size });
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 z-40 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-background-secondary rounded-lg shadow-xl w-full max-w-2xl flex flex-col" onClick={e => e.stopPropagation()}>
        <header className="p-4 border-b border-border-neutral flex justify-between items-center flex-shrink-0">
          <h2 className="text-xl font-bold text-text-primary">Appearance Settings</h2>
          <button onClick={onClose} className="text-text-secondary hover:text-text-primary transition-colors text-2xl font-bold leading-none p-1">&times;</button>
        </header>

        <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh]">
          <div className="space-y-3">
            <h3 className="text-lg font-medium text-text-primary">Theme</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {themeService.themes.map(theme => (
                <div key={theme.id} onClick={() => themeService.setTheme(theme.id)} className="cursor-pointer">
                  <div className={`h-16 w-full rounded-md border-2 flex items-end p-2 theme-preview theme-${theme.id} ${activeTheme === theme.id ? 'border-primary-500' : 'border-border-neutral'}`}>
                    <div className="w-4 h-4 rounded-full bg-primary-500"></div>
                  </div>
                  <p className={`text-center mt-2 text-sm ${activeTheme === theme.id ? 'text-primary-500 font-bold' : 'text-text-primary'}`}>{theme.name}</p>
                </div>
              ))}
            </div>
          </div>

          <ImageControl 
            label="Background Image"
            imageUrl={settings.backgroundImage}
            onUpload={(file) => handleFileUpload(file, 'background')}
            onGenerate={(mode) => handleGenerate('background', mode)}
            onClear={() => handleClear('background')}
            isGenerating={isGeneratingBg}
            canAutoGenerate={canAutoGenerate}
            canCharacterGenerate={canCharacterGenerate}
          />
          <ImageControl 
            label="Banner Image"
            imageUrl={settings.bannerImage}
            onUpload={(file) => handleFileUpload(file, 'banner')}
            onGenerate={(mode) => handleGenerate('banner', mode)}
            onClear={() => handleClear('banner')}
            isGenerating={isGeneratingBanner}
            canAutoGenerate={canAutoGenerate}
            canCharacterGenerate={canCharacterGenerate}
          />

          <div className="space-y-3 pt-6 border-t border-border-neutral">
            <h3 className="text-lg font-medium text-text-primary">Avatar Size</h3>
            <p className="text-sm text-text-secondary">Controls the size of character avatars displayed next to messages in this chat.</p>
            <div className="flex items-center space-x-4">
                {(['small', 'medium', 'large'] as const).map(size => (
                    <label key={size} className="flex items-center space-x-2 cursor-pointer">
                        <input
                            type="radio"
                            name="avatar-size"
                            value={size}
                            checked={(settings.avatarSize || 'medium') === size}
                            onChange={() => handleAvatarSizeChange(size)}
                            className="h-4 w-4 text-primary-600 border-border-strong bg-background-primary focus:ring-primary-500"
                        />
                        <span className="capitalize text-text-primary">{size}</span>
                    </label>
                ))}
            </div>
          </div>

        </div>

        <footer className="p-4 border-t border-border-neutral flex justify-end">
            <button onClick={onClose} className="py-2 px-4 rounded-md text-text-primary bg-background-tertiary hover:bg-opacity-80">Close</button>
        </footer>
      </div>
      {inputModal && (
        <InputModal 
            title={inputModal.title}
            label={inputModal.label}
            onConfirm={inputModal.onConfirm}
            onCancel={() => setInputModal(null)}
        />
      )}
    </div>
  );
};

import React from 'react';

export interface CryptoKeys {
    publicKey: JsonWebKey;
    privateKey: JsonWebKey;
}

export interface Message {
  role: 'user' | 'model' | 'narrator';
  content: string;
  timestamp: string;
  characterId?: string; // Identifies which character sent a 'model' message
  attachment?: {
    type: 'image';
    status: 'loading' | 'done' | 'error';
    url?: string;
    prompt?: string;
  };
  // New security fields
  signature?: string; // Signed by user or character's private key
  publicKeyJwk?: JsonWebKey; // Public key of the signer for verification
}

export interface UISettings {
  backgroundImage?: string; // Now stores an image ID like 'nexus-image://uuid'
  bannerImage?: string; // Now stores an image ID
  avatarSize?: 'small' | 'medium' | 'large';
}

export interface ChatSession {
  id: string;
  characterIds: string[];
  name: string;
  messages: Message[];
  isArchived?: boolean;
  uiSettings?: UISettings;
  lorebookIds?: string[]; // New: Link to active lorebooks
}

export interface ApiConfig {
  service: 'default' | 'gemini' | 'openai';
  apiKey?: string;
  apiEndpoint?: string; // Base URL for OpenAI-compatible
  model?: string;
  rateLimit?: number; // Delay in milliseconds between requests
}

export interface EmbeddingConfig {
  service: 'gemini' | 'openai';
  apiKey?: string;
  apiEndpoint?: string;
  model?: string;
}

export interface RagSource {
    id: string;
    fileName: string;
    fileType: string;
    createdAt: string;
}

export interface Character {
  id:string;
  name: string;
  description: string;
  personality: string; // Will be used as Role Instruction
  avatarUrl: string; // Now stores an image ID like 'nexus-image://uuid'
  tags: string[];
  createdAt: string;
  apiConfig?: ApiConfig;
  // New fields for more detailed characters
  physicalAppearance?: string;
  personalityTraits?: string; // Comma-separated
  lore?: string[];
  memory?: string;
  voiceURI?: string; // For Text-to-Speech
  firstMessage?: string; // New: For character card compatibility
  characterType?: 'character' | 'narrator'; // New: Distinguish between persona and scenario bots

  // Advanced Features
  backstory?: string; // Historical context
  useSearchGrounding?: boolean; // Enable Google Search
  thinkingBudget?: number; // 0 = off, >0 = token budget for reasoning

  // Memory Management
  summaryApiConfig?: ApiConfig; // Dedicated LLM for memory/context operations

  // New RAG fields
  ragEnabled?: boolean;
  embeddingConfig?: EmbeddingConfig;
  ragSources?: RagSource[];
  // New per-character plugin fields
  pluginEnabled?: boolean;
  pluginCode?: string;
  // New security fields
  keys?: CryptoKeys; // Character's own signing key pair
  signature?: string; // Signed by the USER's master private key
  userPublicKeyJwk?: JsonWebKey; // User's public key that signed this character
  isArchived?: boolean;

  // Vault Integration
  vaultAttachmentIds?: string[]; // IDs of files from Vault granted to this character
}

export interface Plugin {
  id: string;
  name: string;
  description: string;
  code: string;
  enabled: boolean;
  settings?: {
    [key:string]: any;
  };
}

export interface LorebookEntry {
    id: string;
    keys: string[];
    content: string;
}

export interface Lorebook {
    id: string;
    name: string;
    description: string;
    entries: LorebookEntry[];
}

// --- Vault Types ---
export interface VaultItem {
  id: string;
  parentId: string; // 'root', 'not-mine', or a folder UUID
  name: string;
  type: 'file' | 'folder';
  mimeType?: string; // e.g., 'image/png', 'application/json'
  content?: string; // Base64 string or JSON string
  size?: number;
  createdAt: string;
  isLocked?: boolean; // If true, requires specific password to open (simulated)
}

export interface AppData {
  characters: Character[];
  chatSessions: ChatSession[];
  plugins?: Plugin[];
  lorebooks?: Lorebook[]; // New: Store all lorebooks
  // New security field
  userKeys?: CryptoKeys;
}

// Types for the secure plugin API bridge
export type GeminiApiRequest = 
  | { type: 'generateContent'; prompt: string }
  | { type: 'generateImage'; prompt: string, settings?: { [key: string]: any } };

export interface PluginApiRequest {
  ticket: number;
  apiRequest: GeminiApiRequest;
}

export interface PluginApiResponse {
  ticket: number;
  result?: any;
  error?: string;
}

// RAG Types
export interface VectorChunk {
    id: string; // chunk-[uuid]
    characterId: string;
    sourceId: string;
    content: string;
    embedding: number[];
}

// Type for the new confirmation modal
export interface ConfirmationRequest {
  message: React.ReactNode;
  onConfirm: () => void;
  onCancel: () => void;
}

import { AppData, ChatSession, VectorChunk, Character, VaultItem } from '../types.ts';
import { STORAGE_KEY_DATA, STORAGE_KEY_PASS_VERIFIER, STORAGE_KEY_SALT } from '../constants.ts';
import { logger } from './loggingService.ts';

// --- Production-Grade Encryption using Web Crypto API ---
// This service implements strong, authenticated encryption for all user data.
// - Key Derivation: PBKDF2 with 100,000 iterations and a unique salt.
// - Encryption: AES-GCM with a 256-bit key.
// - IV Management: A unique 12-byte Initialization Vector (IV) is generated for each encryption
//   operation and prepended to the ciphertext.
// This ensures confidentiality, integrity, and authenticity of the stored data.

let masterCryptoKey: CryptoKey | null = null;
// This is kept ONLY for the one-time migration of legacy data
let masterPasswordForMigration: string | null = null; 

// --- Web Crypto API Helpers ---

const deriveKey = async (password: string, salt: Uint8Array): Promise<CryptoKey> => {
    const encoder = new TextEncoder();
    const baseKey = await window.crypto.subtle.importKey(
        'raw',
        encoder.encode(password),
        { name: 'PBKDF2' },
        false,
        ['deriveKey']
    );
    return window.crypto.subtle.deriveKey(
        {
            name: 'PBKDF2',
            salt: salt,
            iterations: 100000,
            hash: 'SHA-256'
        },
        baseKey,
        { name: 'AES-GCM', length: 256 },
        true,
        ['encrypt', 'decrypt']
    );
};

const arrayBufferToBase64 = (buffer: ArrayBuffer): string => {
    let binary = '';
    const bytes = new Uint8Array(buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return window.btoa(binary);
};

const base64ToArrayBuffer = (base64: string): ArrayBuffer => {
    const binary_string = window.atob(base64);
    const len = binary_string.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binary_string.charCodeAt(i);
    }
    return bytes.buffer;
};

const encryptData = async (data: string, key: CryptoKey): Promise<string> => {
    const encoder = new TextEncoder();
    const dataBuffer = encoder.encode(data);
    const iv = window.crypto.getRandomValues(new Uint8Array(12)); // 12 bytes is recommended for AES-GCM

    const encryptedBuffer = await window.crypto.subtle.encrypt(
        { name: 'AES-GCM', iv: iv },
        key,
        dataBuffer
    );

    // Prepend IV to the ciphertext for storage. This is a standard and secure practice.
    const combinedBuffer = new Uint8Array(iv.length + encryptedBuffer.byteLength);
    combinedBuffer.set(iv);
    combinedBuffer.set(new Uint8Array(encryptedBuffer), iv.length);

    return arrayBufferToBase64(combinedBuffer);
};

const decryptData = async (encryptedBase64: string, key: CryptoKey): Promise<string> => {
    const combinedBuffer = base64ToArrayBuffer(encryptedBase64);

    // Extract IV from the start of the buffer
    const iv = combinedBuffer.slice(0, 12);
    const ciphertext = combinedBuffer.slice(12);

    const decryptedBuffer = await window.crypto.subtle.decrypt(
        { name: 'AES-GCM', iv: iv },
        key,
        ciphertext
    );

    const decoder = new TextDecoder();
    return decoder.decode(decryptedBuffer);
};

// --- Public Ad-Hoc Encryption for Sharing ---
// These functions allow encrypting specific pieces of data with a specific password
// totally separate from the master database key. Used for the Vault "Secure Share".

export const encryptPackage = async (data: string, password: string): Promise<string> => {
    const salt = window.crypto.getRandomValues(new Uint8Array(16));
    const key = await deriveKey(password, salt);
    const encrypted = await encryptData(data, key);

    // Package format: JSON { salt: base64, data: base64 }
    const packageObj = {
        salt: arrayBufferToBase64(salt),
        data: encrypted
    };
    return JSON.stringify(packageObj);
};

export const decryptPackage = async (packageJson: string, password: string): Promise<string> => {
    try {
        const pkg = JSON.parse(packageJson);
        if (!pkg.salt || !pkg.data) throw new Error("Invalid package format");

        const salt = new Uint8Array(base64ToArrayBuffer(pkg.salt));
        const key = await deriveKey(password, salt);
        return await decryptData(pkg.data, key);
    } catch (e) {
        throw new Error("Decryption failed. Wrong password or corrupted file.");
    }
};


// --- Legacy XOR Cipher (for migration only) ---

const legacySimpleXOR = (data: string, key: string): string => {
  let output = '';
  for (let i = 0; i < data.length; i++) {
    output += String.fromCharCode(data.charCodeAt(i) ^ key.charCodeAt(i % key.length));
  }
  return output;
};

const legacyDecrypt = (encryptedData: string, masterKey: string): string => {
    if (!masterKey) throw new Error('Legacy master key is not set for migration.');
    const utf16ToBinary = (str: string): string => unescape(encodeURIComponent(str));
    const binaryToUtf16 = (binary: string): string => decodeURIComponent(escape(binary));

    const binaryString = atob(encryptedData);
    const xorResult = binaryToUtf16(binaryString);
    return legacySimpleXOR(xorResult, masterKey);
};

// --- IndexedDB setup ---
const DB_NAME = 'AINexusDB';
const STORE_NAME = 'appDataStore';
const VECTOR_STORE_NAME = 'vectorStore';
const IMAGE_STORE_NAME = 'imageStore';
const VAULT_STORE_NAME = 'vaultStore'; // New Store
const DB_VERSION = 4; // Increment Version

let dbPromise: Promise<IDBDatabase> | null = null;

const getDB = (): Promise<IDBDatabase> => {
    if (!dbPromise) {
        dbPromise = new Promise((resolve, reject) => {
            if (typeof indexedDB === 'undefined') {
                return reject(new Error('IndexedDB is not supported in this browser.'));
            }
            const request = indexedDB.open(DB_NAME, DB_VERSION);

            request.onerror = () => {
                logger.error("IndexedDB error:", request.error);
                reject("Error opening DB");
            };
            request.onsuccess = () => {
                resolve(request.result);
            };
            request.onupgradeneeded = (event) => {
                const db = (event.target as IDBOpenDBRequest).result;
                if (!db.objectStoreNames.contains(STORE_NAME)) {
                    db.createObjectStore(STORE_NAME);
                }
                if (!db.objectStoreNames.contains(VECTOR_STORE_NAME)) {
                    const vectorStore = db.createObjectStore(VECTOR_STORE_NAME, { keyPath: 'id' });
                    vectorStore.createIndex('characterId', 'characterId', { unique: false });
                    vectorStore.createIndex('sourceId', 'sourceId', { unique: false });
                }
                if (!db.objectStoreNames.contains(IMAGE_STORE_NAME)) {
                    db.createObjectStore(IMAGE_STORE_NAME);
                }
                if (!db.objectStoreNames.contains(VAULT_STORE_NAME)) {
                    // New vault store
                    const vaultStore = db.createObjectStore(VAULT_STORE_NAME, { keyPath: 'id' });
                    vaultStore.createIndex('parentId', 'parentId', { unique: false });
                }
            };
        });
    }
    return dbPromise;
};

const getFromDB = async (key: string): Promise<any> => {
    const db = await getDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readonly');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.get(key);
        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve(request.result);
    });
};

const setToDB = async (key: string, value: any): Promise<void> => {
    const db = await getDB();
    return new Promise<void>((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readwrite');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.put(value, key);
        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve();
    });
};

const migrateKey = async (key: string) => {
    try {
        const lsValue = localStorage.getItem(key);
        if (lsValue !== null) {
            await setToDB(key, lsValue);
localStorage.removeItem(key);
            logger.log(`Migrated '${key}' from localStorage to IndexedDB.`);
        }
    } catch (e) {
        logger.error(`Failed to migrate '${key}' to IndexedDB:`, e);
    }
};

export const hasMasterPassword = async (): Promise<boolean> => {
    await migrateKey(STORAGE_KEY_PASS_VERIFIER);
    const verifier = await getFromDB(STORAGE_KEY_PASS_VERIFIER);
    return verifier !== undefined && verifier !== null;
};

export const setMasterPassword = async (password: string): Promise<void> => {
    masterPasswordForMigration = password;

    // Generate a new salt for the new password
    const salt = window.crypto.getRandomValues(new Uint8Array(16));
    const key = await deriveKey(password, salt);
    masterCryptoKey = key;

    const verifier = await encryptData('password_is_correct', key);

    await setToDB(STORAGE_KEY_SALT, salt);
    await setToDB(STORAGE_KEY_PASS_VERIFIER, verifier);

    // Clear any old localStorage value on new password set
    localStorage.removeItem(STORAGE_KEY_PASS_VERIFIER);
    localStorage.removeItem(STORAGE_KEY_SALT);
};

export const verifyMasterPassword = async (password: string): Promise<boolean> => {
    masterPasswordForMigration = password; // Keep for potential data migration

    await migrateKey(STORAGE_KEY_PASS_VERIFIER);
    await migrateKey(STORAGE_KEY_SALT);

    const salt = await getFromDB(STORAGE_KEY_SALT);
    const verifier = await getFromDB(STORAGE_KEY_PASS_VERIFIER);
    if (!verifier) return false;

    if (salt) {
        // --- Modern Path (AES-GCM) ---
        try {
            const key = await deriveKey(password, salt);
            masterCryptoKey = key;
            const decrypted = await decryptData(verifier, key);
            return decrypted === 'password_is_correct';
        } catch (e) {
            return false;
        }
    } else {
        // --- Legacy Path (XOR) for migration ---
        try {
            const decrypted = legacyDecrypt(verifier, password);
            // If legacy login is correct, masterCryptoKey remains null.
            // This signals to loadData() that a migration is needed.
            return decrypted === 'password_is_correct';
        } catch (e) {
            return false;
        }
    }
};

export const saveData = async (data: AppData): Promise<void> => {
    if (!masterCryptoKey) throw new Error("Cannot save data: master key not available. This may happen if a legacy login occurred without a data load/migration.");

    const jsonString = JSON.stringify(data);
    const encryptedData = await encryptData(jsonString, masterCryptoKey);
    try {
        await setToDB(STORAGE_KEY_DATA, encryptedData);
    } catch (e) {
        logger.error("Failed to save data to IndexedDB:", e);
        throw e;
    }
};

// FIX: Add loadData function to load and decrypt data.
export const loadData = async (): Promise<AppData> => {
    await migrateKey(STORAGE_KEY_DATA);
    const encryptedData = await getFromDB(STORAGE_KEY_DATA);

    if (!encryptedData) {
        logger.log("No data found, returning default structure.");
        return { characters: [], chatSessions: [], plugins: [], lorebooks: [] };
    }

    if (masterCryptoKey) {
        // Modern path: AES-GCM key is available
        try {
            const jsonString = await decryptData(encryptedData, masterCryptoKey);
            return JSON.parse(jsonString);
        } catch (e) {
            logger.error("Failed to decrypt data with modern key. Data might be corrupt.", e);
            throw new Error("Failed to decrypt data.");
        }
    } else if (masterPasswordForMigration) {
        // Legacy path: login was successful with XOR, now migrate the data
        logger.log("Legacy data detected. Attempting migration...");
        try {
            const jsonString = legacyDecrypt(encryptedData, masterPasswordForMigration);
            const data = JSON.parse(jsonString);

            // Now, we need a new AES key to re-encrypt. Let's create one.
            const salt = window.crypto.getRandomValues(new Uint8Array(16));
            const newKey = await deriveKey(masterPasswordForMigration, salt);
            masterCryptoKey = newKey; // Set the new key for future saves

            // Re-save the data with the new encryption
            await saveData(data);

            // Update the verifier and salt to use the new encryption standard
            const verifier = await encryptData('password_is_correct', newKey);
            await setToDB(STORAGE_KEY_SALT, salt);
            await setToDB(STORAGE_KEY_PASS_VERIFIER, verifier);

            logger.log("Data migration to AES-GCM successful.");
            return data;
        } catch (e) {
            logger.error("Failed to decrypt legacy data during migration.", e);
            throw new Error("Failed to migrate legacy data.");
        }
    } else {
        throw new Error("Cannot load data: no master key available.");
    }
};

// --- Vector DB Operations ---

export const saveVectorChunks = async (chunks: VectorChunk[]): Promise<void> => {
    const db = await getDB();
    return new Promise<void>((resolve, reject) => {
        const transaction = db.transaction(VECTOR_STORE_NAME, 'readwrite');
        const store = transaction.objectStore(VECTOR_STORE_NAME);
        chunks.forEach(chunk => {
            store.put(chunk);
        });
        transaction.oncomplete = () => resolve();
        transaction.onerror = () => reject(transaction.error);
    });
};

export const getVectorChunksByCharacter = async (characterId: string): Promise<VectorChunk[]> => {
    const db = await getDB();
    return new Promise<VectorChunk[]>((resolve, reject) => {
        const transaction = db.transaction(VECTOR_STORE_NAME, 'readonly');
        const store = transaction.objectStore(VECTOR_STORE_NAME);
        const index = store.index('characterId');
        const request = index.getAll(characterId);
        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve(request.result);
    });
};

export const deleteVectorChunksBySource = async (sourceId: string): Promise<void> => {
    const db = await getDB();
    return new Promise<void>((resolve, reject) => {
        const transaction = db.transaction(VECTOR_STORE_NAME, 'readwrite');
        const store = transaction.objectStore(VECTOR_STORE_NAME);
        const index = store.index('sourceId');
        const request = index.openCursor(sourceId);

        request.onsuccess = () => {
            const cursor = request.result;
            if (cursor) {
                cursor.delete();
                cursor.continue();
            }
        };
        transaction.oncomplete = () => resolve();
        transaction.onerror = () => reject(transaction.error);
    });
};

// --- Vault Operations ---

export const saveVaultItem = async (item: VaultItem): Promise<void> => {
    // Encrypt the item content itself using the MASTER key before storing in IDB
    // This ensures local security (at rest).
    // Note: When 'Sharing', we use a separate encryption flow.

    if (!masterCryptoKey) throw new Error("Vault locked.");

    // We clone the item to avoid mutating the in-memory state
    const itemToStore = { ...item };

    if (itemToStore.content) {
        itemToStore.content = await encryptData(itemToStore.content, masterCryptoKey);
    }

    const db = await getDB();
    return new Promise<void>((resolve, reject) => {
        const transaction = db.transaction(VAULT_STORE_NAME, 'readwrite');
        const store = transaction.objectStore(VAULT_STORE_NAME);
        const request = store.put(itemToStore);
        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve();
    });
};

export const deleteVaultItem = async (id: string): Promise<void> => {
    const db = await getDB();
    return new Promise<void>((resolve, reject) => {
        const transaction = db.transaction(VAULT_STORE_NAME, 'readwrite');
        const store = transaction.objectStore(VAULT_STORE_NAME);
        const request = store.delete(id);
        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve();
    });
};

export const getVaultItems = async (parentId?: string): Promise<VaultItem[]> => {
    if (!masterCryptoKey) throw new Error("Vault locked.");

    const db = await getDB();
    return new Promise<VaultItem[]>((resolve, reject) => {
        const transaction = db.transaction(VAULT_STORE_NAME, 'readonly');
        const store = transaction.objectStore(VAULT_STORE_NAME);
        let request;

        if (parentId) {
            const index = store.index('parentId');
            request = index.getAll(parentId);
        } else {
            request = store.getAll();
        }

        request.onerror = () => reject(request.error);
        request.onsuccess = async () => {
            const items = request.result as VaultItem[];
            // Decrypt content on the fly
            const decryptedItems = await Promise.all(items.map(async (item) => {
                if (item.content) {
                    try {
                        item.content = await decryptData(item.content, masterCryptoKey!);
                    } catch (e) {
                        logger.error("Failed to decrypt vault item", e);
                        item.content = "Error: Decryption failed";
                    }
                }
                return item;
            }));
            resolve(decryptedItems);
        };
    });
};

export const getVaultItemsByIds = async (ids: string[]): Promise<VaultItem[]> => {
    if (!masterCryptoKey) throw new Error("Vault locked.");
    if (!ids || ids.length === 0) return [];

    const db = await getDB();
    const transaction = db.transaction(VAULT_STORE_NAME, 'readonly');
    const store = transaction.objectStore(VAULT_STORE_NAME);

    const promises = ids.map(id => {
        return new Promise<VaultItem | undefined>((resolve, reject) => {
            const request = store.get(id);
            request.onerror = () => resolve(undefined); // Skip failed items
            request.onsuccess = async () => {
                const item = request.result as VaultItem;
                if (item && item.content) {
                    try {
                        item.content = await decryptData(item.content, masterCryptoKey!);
                    } catch (e) {
                        logger.error(`Failed to decrypt vault item ${id}`, e);
                        item.content = "Error: Decryption failed";
                    }
                }
                resolve(item);
            };
        });
    });

    const results = await Promise.all(promises);
    return results.filter((item): item is VaultItem => item !== undefined);
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ApiConfig, Character, Message } from "../types";
import { logger } from "./loggingService";

// Helper to convert blob to base64
export const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
            const result = reader.result as string;
            resolve(result);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });
};

const fetchWithRetry = async (
    url: RequestInfo, 
    options: RequestInit, 
    maxRetries = 3, 
    initialDelay = 2000,
    logError = true
): Promise<Response> => {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const response = await fetch(url, options);

            if (response.status === 429) {
                if (attempt + 1 >= maxRetries) {
                    if (logError) logger.warn(`API rate limit exceeded. All ${maxRetries} retries failed. Returning final error response.`);
                    return response;
                }
                const delay = initialDelay * Math.pow(2, attempt) + Math.random() * 1000;
                logger.warn(`API rate limit exceeded. Retrying in ${Math.round(delay / 1000)}s... (Attempt ${attempt + 1}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
                attempt++;
                continue;
            }
            return response;

        } catch (error) {
             if (attempt + 1 >= maxRetries) {
                if (logError) logger.error(`API request failed after ${maxRetries} attempts due to network errors.`, error);
                throw error; 
            }
            const delay = initialDelay * Math.pow(2, attempt) + Math.random() * 1000;
            if (logError) logger.warn(`Fetch failed due to a network error. Retrying in ${Math.round(delay / 1000)}s...`, error);
            await new Promise(resolve => setTimeout(resolve, delay));
            attempt++;
        }
    }
    throw new Error(`API request failed to complete after ${maxRetries} attempts.`);
};

const streamOpenAIChatResponse = async (
    config: ApiConfig,
    systemInstruction: string,
    history: Message[],
    onChunk: (chunk: string) => void
): Promise<void> => {
    try {
        const mappedMessages = history
            .filter(msg => msg.role === 'user' || msg.role === 'model' || msg.role === 'narrator')
            .map(msg => {
                const role = msg.role === 'model' ? 'assistant' : 'user';
                const content = msg.role === 'narrator' ? `[NARRATOR]: ${msg.content}` : msg.content;
                return { role, content };
            });

        const mergedMessages = [];
        if (mappedMessages.length > 0) {
            mergedMessages.push(mappedMessages[0]);
            for (let i = 1; i < mappedMessages.length; i++) {
                const prev = mergedMessages[mergedMessages.length - 1];
                const curr = mappedMessages[i];
                if (prev.role === curr.role) {
                    prev.content += `\n\n${curr.content}`; 
                } else {
                    mergedMessages.push(curr);
                }
            }
        }

        if (mergedMessages.length > 0 && mergedMessages[mergedMessages.length - 1].role === 'assistant') {
            if (mergedMessages.length > 1) {
                mergedMessages[mergedMessages.length - 1].role = 'user';
            } else {
                logger.warn("OpenAI stream called with a history containing only a single assistant message. This will likely fail.");
            }
        }

        const messages = [
            { role: "system", content: systemInstruction },
            ...mergedMessages
        ];

        const response = await fetchWithRetry((config.apiEndpoint || '').trim(), {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${config.apiKey?.trim() || 'ollama'}`,
            },
            body: JSON.stringify({
                model: config.model?.trim() || 'default',
                messages: messages,
                stream: true,
            }),
        });

        if (!response.ok) {
            const errorBody = await response.text();
            if (response.status === 429) {
                throw new Error(`Rate limit exceeded: ${errorBody}`);
            }
            throw new Error(`API request failed with status ${response.status}: ${errorBody}`);
        }

        const reader = response.body?.getReader();
        if (!reader) throw new Error("Could not get response reader.");

        const decoder = new TextDecoder();
        let buffer = '';

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            buffer += decoder.decode(value, { stream: true });
            const lines = buffer.split('\n');
            buffer = lines.pop() || '';

            for (const line of lines) {
                if (line.startsWith('data: ')) {
                    const jsonStr = line.substring(6);
                    if (jsonStr === '[DONE]') {
                        return;
                    }
                    try {
                        const parsed = JSON.parse(jsonStr);
                        const chunk = parsed.choices[0]?.delta?.content;
                        if (chunk) {
                            onChunk(chunk);
                        }
                    } catch (e) {
                        logger.warn("Failed to parse stream chunk JSON:", jsonStr);
                    }
                }
            }
        }
    } catch (error) {
        logger.error("Error in OpenAI-compatible stream:", error);
        onChunk(`Sorry, I encountered an error with the OpenAI-compatible API: ${error instanceof Error ? error.message : String(error)}`);
    }
};

const streamGeminiChatResponse = async (
    apiKey: string,
    model: string,
    systemInstruction: string,
    history: Message[],
    onChunk: (chunk: string) => void,
    character?: Character
): Promise<void> => {
    try {
        const ai = new GoogleGenAI({ apiKey });

        const pastMessages = history.slice(0, -1);
        const newMessage = history[history.length - 1];

        const geminiHistory = pastMessages
            .filter(m => m.role === 'user' || m.role === 'model')
            .map(m => ({
                role: m.role === 'model' ? 'model' : 'user',
                parts: [{ text: m.content }]
            }));

        // Configuration for tools and thinking
        const config: any = {
            systemInstruction: systemInstruction,
        };

        // Add Search Tool if enabled
        if (character?.useSearchGrounding) {
            config.tools = [{ googleSearch: {} }];
        }

        // Add Thinking Config if enabled (budget > 0)
        // Thinking is only available on 2.5/3.0 models.
        if (character?.thinkingBudget && character.thinkingBudget > 0) {
            config.thinkingConfig = { thinkingBudget: character.thinkingBudget };
        }

        const chat = ai.chats.create({
            model: model || 'gemini-3-flash-preview',
            config: config,
            history: geminiHistory
        });

        const prompt = newMessage.content || (newMessage.role === 'user' ? '...' : 'Continue');

        const result = await chat.sendMessageStream({ message: prompt });

        for await (const chunk of result) {
            // Handle search grounding chunks
            if (chunk.groundingMetadata?.groundingChunks) {
                const chunks = chunk.groundingMetadata.groundingChunks;
                // We can construct a footnote string or just append. 
                // For simplicity in this text stream, we append sources at the end if possible, 
                // but since it's streaming, we might just log them or append a marker.
                // NOTE: The main UI just displays text.
            }
            if (chunk.text) {
                onChunk(chunk.text);
            }
        }
    } catch (error) {
         logger.error("Error in Gemini stream:", error);
         onChunk(`[Error: ${error instanceof Error ? error.message : String(error)}]`);
    }
};

export const streamChatResponse = async (
    character: Character,
    participants: Character[],
    history: Message[],
    onChunk: (chunk: string) => void,
    systemOverride?: string
): Promise<void> => {
    // Construct System Instruction
    let systemInstruction = `You are playing the role of ${character.name}. ${character.description}\n\nPersonality: ${character.personality}`;
    if (character.physicalAppearance) systemInstruction += `\nAppearance: ${character.physicalAppearance}`;
    if (character.personalityTraits) systemInstruction += `\nTraits: ${character.personalityTraits}`;
    if (character.backstory) systemInstruction += `\nBackstory: ${character.backstory}`;
    if (character.lore && character.lore.length > 0) systemInstruction += `\nLore: ${character.lore.join(' ')}`;

    // Add Capability Instructions
    systemInstruction += `\n\n[CAPABILITIES]:
    1. INLINE IMAGES: If you want to show the user an image of what is happening or what you are imagining, output the tag: [generate_image: detailed visual description].
    2. DYNAMIC AVATAR: You can change your profile picture to match your current emotion, outfit, or situation. To do this, output the tag: [change_avatar: description of new look]. E.g. [change_avatar: smiling warmly wearing a summer dress]. Use this sparingly for effect.
    `;

    if (participants.length > 1) {
        const otherNames = participants.filter(p => p.id !== character.id).map(p => p.name).join(', ');
        systemInstruction += `\n\nYou are in a chat with: ${otherNames}.`;
    }

    if (systemOverride) {
        systemInstruction += `\n\n${systemOverride}`;
    }

    const config = character.apiConfig || { service: 'default' };

    if (config.service === 'openai') {
        return streamOpenAIChatResponse(config, systemInstruction, history, onChunk);
    } else {
        // Default to Gemini
        const apiKey = config.apiKey || process.env.API_KEY;
        if (!apiKey) {
            onChunk("Error: No API Key configured for Gemini.");
            return;
        }
        // Map common model aliases or use default
        let model = config.model || 'gemini-3-flash-preview';
        return streamGeminiChatResponse(apiKey, model, systemInstruction, history, onChunk, character);
    }
};

export const streamGenericResponse = async (
    systemInstruction: string,
    prompt: string,
    onChunk: (chunk: string) => void
): Promise<void> => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        onChunk("Error: No API Key available.");
        return;
    }
    try {
        const ai = new GoogleGenAI({ apiKey });
        const result = await ai.models.generateContentStream({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { systemInstruction }
        });
        for await (const chunk of result) {
            onChunk(chunk.text);
        }
    } catch (error) {
        logger.error("Error in generic stream:", error);
        onChunk(`[Error: ${error instanceof Error ? error.message : String(error)}]`);
    }
};

export const generateContent = async (prompt: string, config?: ApiConfig): Promise<string> => {
    // If specific config is passed (e.g. for memory management), use it.
    if (config && config.service === 'openai') {
        // Simple one-shot for OpenAI
        let result = '';
        await streamOpenAIChatResponse(config, "You are a helpful assistant.", [{role: 'user', content: prompt, timestamp: ''}], (chunk) => result += chunk);
        return result;
    }

    const apiKey = config?.apiKey || process.env.API_KEY;
    if (!apiKey) throw new Error("No API Key available.");

    const ai = new GoogleGenAI({ apiKey });
    const modelName = config?.model || 'gemini-3-flash-preview';

    const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt
    });
    return response.text || '';
};

const buildImagePrompt = (prompt: string, settings: { [key: string]: any }): string => {
    let stylePrompt = '';
    if (settings.style && settings.style !== 'Default (None)') {
        if (settings.style === 'Custom' && settings.customStylePrompt) {
            stylePrompt = `${settings.customStylePrompt}, `;
        } else if (settings.style !== 'Custom') {
             stylePrompt = `${settings.style} style, `;
        }
    }
    const negativePrompt = settings.negativePrompt ? `. Negative prompt: ${settings.negativePrompt}` : '';
    return `${stylePrompt}${prompt}${negativePrompt}`;
};

const generateOpenAIImage = async (prompt: string, settings: { [key: string]: any }): Promise<string> => {
    const fullPrompt = buildImagePrompt(prompt, settings);
    logger.log("Generating OpenAI image with full prompt:", { fullPrompt });

    const response = await fetchWithRetry((settings.apiEndpoint || '').trim(), {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${settings.apiKey?.trim() || 'ollama'}`,
        },
        body: JSON.stringify({
            prompt: fullPrompt,
            model: settings.model?.trim() || 'dall-e-3',
            n: 1,
            size: "1024x1024",
            response_format: "b64_json",
        }),
    });

    if (!response.ok) {
        const errorBody = await response.text();
        throw new Error(`Image generation failed with status ${response.status}: ${errorBody}`);
    }

    const json = await response.json();
    const base64Image = json.data?.[0]?.b64_json;

    if (!base64Image) {
        throw new Error("API response did not contain image data.");
    }
    return `data:image/png;base64,${base64Image}`;
};

const generatePollinationsImage = async (prompt: string, settings: { [key: string]: any }): Promise<string> => {
    const fullPrompt = buildImagePrompt(prompt, settings);
    logger.log("Generating Pollinations image...", { fullPrompt });

    let model = settings.model ? `&model=${encodeURIComponent(settings.model)}` : '';
    const seed = Math.floor(Math.random() * 1000000000);
    const encodedPrompt = encodeURIComponent(fullPrompt);
    let url = `https://pollinations.ai/p/${encodedPrompt}?width=1024&height=1024${model}&seed=${seed}&nologo=true`;

    // Add API Key if present
    if (settings.apiKey) {
        url += `&api_key=${settings.apiKey}`;
    }

    try {
        const response = await fetchWithRetry(url, {
            method: 'GET',
        }, 3, 2000, false);

        if (!response.ok) {
            throw new Error(`Pollinations API failed with status ${response.status}`);
        }

        const blob = await response.blob();
        const base64 = await blobToBase64(blob);
        // blobToBase64 includes prefix usually, but check implementation
        return base64; 
    } catch (error) {
        logger.warn("Pollinations fetch failed (likely CORS), falling back to direct URL.");
        return url;
    }
};

export const generateImageFromPrompt = async (prompt: string, settings: { [key: string]: any }): Promise<string> => {
    const service = settings.service || 'pollinations';

    if (service === 'openai' || service === 'imagerouter') {
        return generateOpenAIImage(prompt, settings);
    } else if (service === 'gemini') {
         const apiKey = settings.apiKey || process.env.API_KEY;
         if (!apiKey) throw new Error("API Key required for Gemini Image Generation");
         const ai = new GoogleGenAI({ apiKey });
         const model = settings.model || 'gemini-2.5-flash-image';
         // Gemini 2.5 Flash Image uses generateContent for images
         const response = await ai.models.generateContent({
             model,
             contents: { parts: [{ text: buildImagePrompt(prompt, settings) }] }
         });

         // Extract image from response
         // Note: Actual extraction depends on model output format which might be base64 in inlineData
         // For nano banana series (gemini-2.5-flash-image), it returns inlineData.
         // We need to iterate parts.
         for (const candidate of response.candidates || []) {
             for (const part of candidate.content.parts) {
                 if (part.inlineData) {
                     return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                 }
             }
         }
         throw new Error("No image data found in Gemini response.");

    } else {
        // Default to Pollinations (handles Hugging Face, AI Horde, etc via URL construction or fallback)
        // Note: For real implementations of Stability/HuggingFace auth, specific handlers would be needed.
        // Pollinations is a good generic fallback proxy.
        return generatePollinationsImage(prompt, settings);
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { VaultItem } from '../types';
import { saveVaultItem, getVaultItems, deleteVaultItem, encryptPackage, decryptPackage } from '../services/secureStorage';
import { logger } from '../services/loggingService';
import { VaultIcon } from './icons/VaultIcon';
import { FolderIcon } from './icons/FolderIcon';
import { DownloadIcon } from './icons/DownloadIcon';
import { TrashIcon } from './icons/TrashIcon';
import { PlusIcon } from './icons/PlusIcon';
import { UploadIcon } from './icons/UploadIcon';
import { LockOpenIcon } from './icons/LockOpenIcon';
import { LockIcon } from './icons/LockIcon';
import { CheckCircleIcon } from './icons/CheckCircleIcon';
import { InputModal } from './InputModal.tsx';

interface VaultProps {
    onClose: () => void;
    mode?: 'manage' | 'select';
    onConfirmSelection?: (selectedIds: string[]) => void;
}

const ROOT_ID = 'root';
const SHARED_ID = 'not-mine';

export const Vault: React.FC<VaultProps> = ({ onClose, mode = 'manage', onConfirmSelection }) => {
    const [currentFolderId, setCurrentFolderId] = useState<string>(ROOT_ID);
    const [items, setItems] = useState<VaultItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [selectedItem, setSelectedItem] = useState<VaultItem | null>(null);
    const [sharePassword, setSharePassword] = useState('');
    const [importPassword, setImportPassword] = useState('');
    const [showShareModal, setShowShareModal] = useState(false);
    const [showImportModal, setShowImportModal] = useState(false);
    const [inputModal, setInputModal] = useState<{ title: string, label: string, onConfirm: (val: string) => void } | null>(null);

    // For select mode
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

    const fileInputRef = useRef<HTMLInputElement>(null);
    const secureImportInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        loadItems(currentFolderId);
    }, [currentFolderId]);

    const loadItems = async (folderId: string) => {
        setLoading(true);
        try {
            const vaultItems = await getVaultItems(folderId);
            // Sort: Folders first, then files
            const sorted = vaultItems.sort((a, b) => {
                if (a.type === b.type) return a.name.localeCompare(b.name);
                return a.type === 'folder' ? -1 : 1;
            });
            setItems(sorted);
        } catch (error) {
            logger.error("Failed to load vault items", error);
        } finally {
            setLoading(false);
        }
    };

    const handleCreateFolder = () => {
        setInputModal({
            title: "Create New Folder",
            label: "Folder Name:",
            onConfirm: async (name) => {
                const newFolder: VaultItem = {
                    id: crypto.randomUUID(),
                    parentId: currentFolderId,
                    name,
                    type: 'folder',
                    createdAt: new Date().toISOString()
                };
                await saveVaultItem(newFolder);
                loadItems(currentFolderId);
                setInputModal(null);
            }
        });
    };

    const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (event) => {
            const content = event.target?.result as string;
            const newItem: VaultItem = {
                id: crypto.randomUUID(),
                parentId: currentFolderId,
                name: file.name,
                type: 'file',
                mimeType: file.type,
                content: content, // This gets encrypted by saveVaultItem
                size: file.size,
                createdAt: new Date().toISOString()
            };

            setLoading(true);
            await saveVaultItem(newItem);
            loadItems(currentFolderId);
            setLoading(false);
        };
        reader.readAsDataURL(file);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure? This cannot be undone.")) return;
        await deleteVaultItem(id);
        // If it's a folder, we strictly should delete children too, 
        // but for this MVP we just delete the entry. Children become orphans (hidden).
        // A robust implementation would recursively delete.
        loadItems(currentFolderId);
        setSelectedItem(null);
    };

    const handleSecureShare = async () => {
        if (!selectedItem || !sharePassword) return;
        if (selectedItem.type === 'folder') {
            alert("Folder sharing not supported in this version. Please zip it or share files individually.");
            return;
        }

        try {
            // Decrypt content (it's loaded decrypted from getVaultItems), then encrypt with share password
            // Note: In getVaultItems, content is already decrypted for us.
            const encryptedPackage = await encryptPackage(JSON.stringify(selectedItem), sharePassword);

            const blob = new Blob([encryptedPackage], { type: 'application/octet-stream' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${selectedItem.name}.nexusvault`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);

            setShowShareModal(false);
            setSharePassword('');
            alert("Secure package generated!");
        } catch (e) {
            logger.error("Sharing failed", e);
            alert("Encryption failed.");
        }
    };

    const handleSecureImport = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        // We need the password first
        if (!importPassword) {
            alert("Please set the decryption password first.");
            // Also clear input here so they can retry selecting
            if (secureImportInputRef.current) secureImportInputRef.current.value = '';
            return;
        }

        const reader = new FileReader();

        const cleanup = () => {
             if (secureImportInputRef.current) secureImportInputRef.current.value = '';
        };

        reader.onload = async (event) => {
            try {
                const encryptedContent = event.target?.result as string;
                // Decrypt
                const decryptedJson = await decryptPackage(encryptedContent, importPassword);
                const importedItem = JSON.parse(decryptedJson) as VaultItem;

                importedItem.id = crypto.randomUUID(); // New ID to avoid conflicts
                importedItem.parentId = SHARED_ID; // Force location
                importedItem.name = `[Imported] ${importedItem.name}`;
                importedItem.createdAt = new Date().toISOString();

                // Ensure Not Mine folder exists
                const notMineFolder: VaultItem = {
                    id: SHARED_ID,
                    parentId: ROOT_ID,
                    name: 'Not Mine (Incoming)',
                    type: 'folder',
                    createdAt: new Date().toISOString()
                };
                // Try to save folder (idempotent overwrite is fine)
                await saveVaultItem(notMineFolder);
                await saveVaultItem(importedItem);

                alert("File imported successfully into 'Not Mine' folder.");

                if (currentFolderId === SHARED_ID) {
                    loadItems(SHARED_ID);
                } else {
                    setCurrentFolderId(SHARED_ID);
                }
                setShowImportModal(false);
                setImportPassword('');

            } catch (error) {
                logger.error("Import failed", error);
                alert("Import failed. Incorrect password or invalid file.");
            } finally {
                cleanup();
            }
        };

        reader.onerror = () => {
             logger.error("Vault import file read error", reader.error);
             alert("Failed to read file.");
             cleanup();
        }

        reader.readAsText(file);
    };

    const downloadFile = (item: VaultItem) => {
        if (!item.content) return;
        const a = document.createElement('a');
        a.href = item.content;
        a.download = item.name;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    };

    const formatSize = (bytes?: number) => {
        if (!bytes) return '0 B';
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
    };

    const toggleSelection = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const handleItemClick = (item: VaultItem) => {
        if (item.type === 'folder') {
            setCurrentFolderId(item.id);
        } else if (mode === 'select') {
            toggleSelection(item.id);
        } else {
            setSelectedItem(item);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/90 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
            <div className="bg-gray-900 border border-green-500/30 rounded-lg shadow-2xl w-full max-w-6xl h-[85vh] flex flex-col overflow-hidden font-mono text-green-400">
                {/* Header */}
                <header className="p-4 border-b border-green-500/30 flex justify-between items-center bg-gray-900/50">
                    <div className="flex items-center space-x-3">
                        <VaultIcon className="w-8 h-8 text-green-500" />
                        <h1 className="text-2xl font-bold tracking-widest uppercase">
                            {mode === 'select' ? 'Select Vault Items' : 'Nexus Secure Vault'}
                        </h1>
                    </div>
                    <button onClick={onClose} className="text-green-500 hover:text-green-300 text-2xl font-bold">&times;</button>
                </header>

                {/* Toolbar */}
                <div className="p-2 border-b border-green-500/30 flex items-center space-x-2 bg-gray-800/50">
                    {currentFolderId !== ROOT_ID && (
                        <button onClick={() => setCurrentFolderId(ROOT_ID)} className="px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded border border-green-500/30 text-sm">
                            &larr; Root
                        </button>
                    )}
                    {mode === 'manage' && (
                        <>
                            <button onClick={handleCreateFolder} className="flex items-center space-x-1 px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded border border-green-500/30 text-sm">
                                <PlusIcon className="w-4 h-4" /> <span>New Folder</span>
                            </button>
                            <input type="file" ref={fileInputRef} onChange={handleUpload} className="hidden" />
                            <button onClick={() => fileInputRef.current?.click()} className="flex items-center space-x-1 px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded border border-green-500/30 text-sm">
                                <UploadIcon className="w-4 h-4" /> <span>Upload File</span>
                            </button>
                            <div className="flex-1"></div>
                            <button onClick={() => setShowImportModal(true)} className="flex items-center space-x-1 px-3 py-1 bg-green-900/30 hover:bg-green-900/50 rounded border border-green-500 text-sm text-green-300">
                                <DownloadIcon className="w-4 h-4" /> <span>Import Secure Pkg</span>
                            </button>
                        </>
                    )}
                    {mode === 'select' && (
                        <>
                            <div className="flex-1"></div>
                            <button 
                                onClick={() => { if(onConfirmSelection) onConfirmSelection(Array.from(selectedIds)); onClose(); }} 
                                disabled={selectedIds.size === 0}
                                className="px-4 py-1 bg-green-600 hover:bg-green-500 text-white rounded font-bold disabled:opacity-50"
                            >
                                Confirm Selection ({selectedIds.size})
                            </button>
                        </>
                    )}
                </div>

                <div className="flex flex-1 overflow-hidden">
                    {/* Sidebar / Quick Access */}
                    <div className="w-48 border-r border-green-500/30 p-4 space-y-2 bg-black/20">
                        <h3 className="text-xs uppercase text-green-600 font-bold mb-2">Locations</h3>
                        <div 
                            onClick={() => setCurrentFolderId(ROOT_ID)}
                            className={`cursor-pointer p-2 rounded ${currentFolderId === ROOT_ID ? 'bg-green-500/20 text-white' : 'hover:bg-green-500/10'}`}
                        >
                            My Files
                        </div>
                        <div 
                            onClick={() => setCurrentFolderId(SHARED_ID)}
                            className={`cursor-pointer p-2 rounded ${currentFolderId === SHARED_ID ? 'bg-green-500/20 text-white' : 'hover:bg-green-500/10'}`}
                        >
                            Not Mine (Incoming)
                        </div>
                    </div>

                    {/* Main Content */}
                    <div className="flex-1 p-4 overflow-y-auto">
                        {loading ? (
                            <div className="text-center mt-10 animate-pulse">Accessing Secure Storage...</div>
                        ) : items.length === 0 ? (
                            <div className="text-center mt-10 text-green-700">Vault Empty.</div>
                        ) : (
                            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                                {items.map(item => (
                                    <div 
                                        key={item.id}
                                        onClick={() => handleItemClick(item)}
                                        className={`group relative p-4 rounded border ${selectedIds.has(item.id) ? 'border-green-400 bg-green-500/20' : (selectedItem?.id === item.id ? 'border-green-400 bg-green-500/10' : 'border-green-500/20 bg-gray-800/30 hover:border-green-500/50')} flex flex-col items-center justify-center cursor-pointer transition-all`}
                                    >
                                        {selectedIds.has(item.id) && <div className="absolute top-2 right-2"><CheckCircleIcon className="w-5 h-5 text-green-400" /></div>}
                                        {item.type === 'folder' ? (
                                            <FolderIcon className="w-12 h-12 text-yellow-500/80 mb-2" />
                                        ) : (
                                            <div className="relative">
                                                {item.mimeType?.startsWith('image/') ? (
                                                    <img src={item.content} className="w-12 h-12 object-cover rounded" alt="thumb" />
                                                ) : (
                                                    <div className="w-12 h-12 flex items-center justify-center bg-gray-700 rounded text-xs text-white">FILE</div>
                                                )}
                                            </div>
                                        )}
                                        <div className="text-xs text-center truncate w-full mt-2" title={item.name}>{item.name}</div>
                                        <div className="text-[10px] text-green-700 mt-1">{formatSize(item.size)}</div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Details / Actions Pane (Only in manage mode) */}
                    {mode === 'manage' && selectedItem && (
                        <div className="w-64 border-l border-green-500/30 p-4 bg-black/20 flex flex-col">
                            <h3 className="text-lg font-bold truncate mb-4 border-b border-green-500/30 pb-2">{selectedItem.name}</h3>
                            <div className="space-y-4 flex-1">
                                <div className="text-sm">
                                    <span className="text-green-700 block text-xs uppercase">Type</span>
                                    {selectedItem.type}
                                </div>
                                <div className="text-sm">
                                    <span className="text-green-700 block text-xs uppercase">Size</span>
                                    {formatSize(selectedItem.size)}
                                </div>
                                <div className="text-sm">
                                    <span className="text-green-700 block text-xs uppercase">Created</span>
                                    {new Date(selectedItem.createdAt).toLocaleDateString()}
                                </div>
                            </div>
                            <div className="mt-4 space-y-2">
                                {selectedItem.type === 'file' && (
                                    <>
                                        <button onClick={() => downloadFile(selectedItem)} className="w-full py-2 bg-green-700 hover:bg-green-600 text-white rounded text-sm flex items-center justify-center space-x-2">
                                            <DownloadIcon className="w-4 h-4"/> <span>Download</span>
                                        </button>
                                        <button onClick={() => setShowShareModal(true)} className="w-full py-2 bg-blue-900/50 border border-blue-500 hover:bg-blue-800/50 text-blue-300 rounded text-sm flex items-center justify-center space-x-2">
                                            <LockOpenIcon className="w-4 h-4"/> <span>Secure Share</span>
                                        </button>
                                    </>
                                )}
                                <button onClick={() => handleDelete(selectedItem.id)} className="w-full py-2 bg-red-900/50 border border-red-500 hover:bg-red-800/50 text-red-300 rounded text-sm flex items-center justify-center space-x-2">
                                    <TrashIcon className="w-4 h-4"/> <span>Delete</span>
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Share Modal */}
            {showShareModal && (
                <div className="absolute inset-0 z-[60] flex items-center justify-center bg-black/80">
                    <div className="bg-gray-800 border border-blue-500 rounded p-6 w-96 text-blue-300">
                        <h3 className="text-lg font-bold mb-4 flex items-center"><LockIcon className="w-5 h-5 mr-2"/> Secure Share</h3>
                        <p className="text-xs mb-4 text-blue-400">
                            Create a password-protected <code>.nexusvault</code> file. You must share the password with the recipient separately.
                        </p>
                        <input 
                            type="password" 
                            placeholder="Set Encryption Password" 
                            className="w-full bg-gray-900 border border-blue-500/50 rounded p-2 mb-4 text-white focus:outline-none focus:border-blue-500"
                            value={sharePassword}
                            onChange={(e) => setSharePassword(e.target.value)}
                        />
                        <div className="flex justify-end space-x-2">
                            <button onClick={() => setShowShareModal(false)} className="px-4 py-2 hover:bg-gray-700 rounded">Cancel</button>
                            <button onClick={handleSecureShare} disabled={!sharePassword} className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded disabled:opacity-50">Generate</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Import Modal */}
            {showImportModal && (
                <div className="absolute inset-0 z-[60] flex items-center justify-center bg-black/80">
                    <div className="bg-gray-800 border border-green-500 rounded p-6 w-96 text-green-300">
                        <h3 className="text-lg font-bold mb-4 flex items-center"><DownloadIcon className="w-5 h-5 mr-2"/> Import Secure Package</h3>
                        <p className="text-xs mb-4 text-green-400">
                            Enter the password provided by the sender to decrypt the file into your "Not Mine" folder.
                        </p>
                        <input 
                            type="password" 
                            placeholder="Decryption Password" 
                            className="w-full bg-gray-900 border border-green-500/50 rounded p-2 mb-4 text-white focus:outline-none focus:border-green-500"
                            value={importPassword}
                            onChange={(e) => setImportPassword(e.target.value)}
                        />
                        <div className="flex space-x-2">
                            <input 
                                type="file" 
                                ref={secureImportInputRef} 
                                accept=".nexusvault" 
                                onChange={handleSecureImport}
                                className="hidden"
                            />
                            <button onClick={() => setShowImportModal(false)} className="px-4 py-2 hover:bg-gray-700 rounded">Cancel</button>
                            <button onClick={() => secureImportInputRef.current?.click()} disabled={!importPassword} className="flex-1 px-4 py-2 bg-green-600 hover:bg-green-500 text-white rounded disabled:opacity-50 text-center">Select File</button>
                        </div>
                    </div>
                </div>
            )}

            {inputModal && (
                <InputModal 
                    title={inputModal.title}
                    label={inputModal.label}
                    onConfirm={inputModal.onConfirm}
                    onCancel={() => setInputModal(null)}
                />
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { Character, RagSource, ApiConfig } from '../types';
import { logger } from '../services/loggingService';
import * as ragService from '../services/ragService';
import * as geminiService from '../services/geminiService';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';
import { UploadIcon } from './icons/UploadIcon';
import { ImageIcon } from './icons/ImageIcon';
import { SpinnerIcon } from './icons/SpinnerIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { CogIcon } from './icons/CogIcon';
import { VaultIcon } from './icons/VaultIcon';

interface CharacterFormProps {
    character: Character | null;
    onSave: (character: Character) => void;
    onCancel: () => void;
    onDeleteRagSource: (characterId: string, sourceId: string) => void;
    onGenerateImage: (prompt: string) => Promise<string | null>;
    onOpenVaultSelection: (onConfirm: (ids: string[]) => void) => void; // Callback to open vault in selection mode
}

export const CharacterForm: React.FC<CharacterFormProps> = ({ character, onSave, onCancel, onDeleteRagSource, onGenerateImage, onOpenVaultSelection }) => {
    const [formState, setFormState] = useState<Character>(character || {
        id: crypto.randomUUID(),
        name: '',
        description: '',
        personality: '',
        backstory: '',
        firstMessage: '',
        avatarUrl: '',
        tags: [],
        createdAt: new Date().toISOString(),
        characterType: 'character',
        ragEnabled: false,
        useSearchGrounding: false,
        thinkingBudget: 0,
        embeddingConfig: { service: 'gemini' },
        vaultAttachmentIds: []
    });

    // Ensure embedding config is initialized even if loading an old character
    useEffect(() => {
        if (character && !character.embeddingConfig) {
            setFormState(prev => ({
                ...prev,
                embeddingConfig: { service: 'gemini' }
            }));
        }
    }, [character]);

    const [indexingStatus, setIndexingStatus] = useState<string | null>(null);
    const [isGeneratingAvatar, setIsGeneratingAvatar] = useState(false);
    const [isGeneratingText, setIsGeneratingText] = useState<string | null>(null); // 'description' | 'personality' etc
    const [activeTab, setActiveTab] = useState<'basic' | 'details' | 'advanced' | 'memory'>('basic');

    const ragFileInputRef = useRef<HTMLInputElement>(null);
    const avatarInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (character) {
            setFormState(character);
        }
    }, [character]);

    const handleChange = (field: keyof Character, value: any) => {
        setFormState(prev => ({ ...prev, [field]: value }));
    };

    const handleNestedChange = (parent: keyof Character, key: string, value: any) => {
        setFormState(prev => ({
            ...prev,
            [parent]: {
                ...(prev[parent] as object),
                [key]: value
            }
        }));
    };

    const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (ev) => {
                handleChange('avatarUrl', ev.target?.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleGenerateAvatar = async () => {
        if (!formState.description) {
            alert("Please enter a description first.");
            return;
        }
        setIsGeneratingAvatar(true);
        try {
            const prompt = `A portrait of a character matching this description: ${formState.description}. ${formState.physicalAppearance || ''} ${formState.name}`;
            const url = await onGenerateImage(prompt);
            if (url) {
                handleChange('avatarUrl', url);
            }
        } catch (e) {
            logger.error("Avatar generation failed", e);
            alert("Failed to generate avatar.");
        } finally {
            setIsGeneratingAvatar(false);
        }
    };

    const handleAIGenerate = async (field: keyof Character, promptTemplate: string) => {
        if (!formState.name) {
            alert("Please enter a character name first.");
            return;
        }
        setIsGeneratingText(field as string);
        try {
            // Use the summaryApiConfig if available, else default
            const config = formState.summaryApiConfig || { service: 'default' };
            const prompt = promptTemplate.replace('{{name}}', formState.name).replace('{{desc}}', formState.description || 'a generic character');

            const content = await geminiService.generateContent(prompt, config);
            handleChange(field, content.trim());
        } catch (e) {
            logger.error(`Failed to generate ${field}`, e);
            alert(`Failed to generate content: ${e instanceof Error ? e.message : String(e)}`);
        } finally {
            setIsGeneratingText(null);
        }
    };

    const handleRagFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        try {
            setIndexingStatus(`Processing "${file.name}"...`);
            const newSource = await ragService.processAndIndexFile(file, formState, (progress) => {
                setIndexingStatus(progress);
            });

            const updatedCharacter = {
                ...formState,
                ragSources: [...(formState.ragSources || []), newSource]
            };
            setFormState(updatedCharacter);
            onSave(updatedCharacter); // Persist immediately
            setIndexingStatus(`Successfully indexed "${file.name}"!`);
        } catch (error) {
            logger.error("File indexing failed:", error);
            setIndexingStatus(`Error indexing "${file.name}": ${error instanceof Error ? error.message : "Unknown error"}`);
        } finally {
            if (ragFileInputRef.current) ragFileInputRef.current.value = "";
            setTimeout(() => setIndexingStatus(null), 5000);
        }
    };

    const handleAttachVaultItems = () => {
        onOpenVaultSelection((selectedIds) => {
            const currentIds = new Set(formState.vaultAttachmentIds || []);
            selectedIds.forEach(id => currentIds.add(id));
            handleChange('vaultAttachmentIds', Array.from(currentIds));
        });
    };

    const handleRemoveVaultItem = (id: string) => {
        const updatedIds = (formState.vaultAttachmentIds || []).filter(vid => vid !== id);
        handleChange('vaultAttachmentIds', updatedIds);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave(formState);
    };

    const renderAIGenButton = (field: keyof Character, prompt: string, tooltip: string) => (
        <button
            type="button"
            onClick={() => handleAIGenerate(field, prompt)}
            disabled={!!isGeneratingText}
            className="absolute top-0 right-0 p-1 text-primary-500 hover:text-primary-400 disabled:opacity-50"
            title={tooltip}
        >
            {isGeneratingText === field ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4"/>}
        </button>
    );

    return (
        <div className="flex-1 flex flex-col bg-background-primary overflow-hidden">
            <header className="p-4 border-b border-border-neutral flex items-center justify-between">
                <h2 className="text-xl font-bold text-text-primary">{character ? 'Edit Character' : 'New Character'}</h2>
                <div className="space-x-3">
                    <button onClick={onCancel} className="px-4 py-2 rounded text-text-primary bg-background-tertiary hover:bg-opacity-80">Cancel</button>
                    <button onClick={handleSubmit} className="px-4 py-2 rounded text-text-accent bg-primary-600 hover:bg-primary-500">Save</button>
                </div>
            </header>

            <div className="flex border-b border-border-neutral bg-background-secondary overflow-x-auto">
                <button onClick={() => setActiveTab('basic')} className={`px-4 py-3 text-sm font-medium ${activeTab === 'basic' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-text-secondary hover:text-text-primary'}`}>Basic Info</button>
                <button onClick={() => setActiveTab('details')} className={`px-4 py-3 text-sm font-medium ${activeTab === 'details' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-text-secondary hover:text-text-primary'}`}>Details & Personality</button>
                <button onClick={() => setActiveTab('advanced')} className={`px-4 py-3 text-sm font-medium ${activeTab === 'advanced' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-text-secondary hover:text-text-primary'}`}>Advanced Logic (RAG/Vault)</button>
                <button onClick={() => setActiveTab('memory')} className={`px-4 py-3 text-sm font-medium ${activeTab === 'memory' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-text-secondary hover:text-text-primary'}`}>Memory & Intelligence</button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8">
                <form onSubmit={handleSubmit} className="max-w-4xl mx-auto space-y-6">

                    {/* --- BASIC INFO TAB --- */}
                    {activeTab === 'basic' && (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fadeIn">
                            <div className="col-span-1 flex flex-col items-center space-y-4">
                                <div className="w-32 h-32 rounded-full bg-background-tertiary overflow-hidden border-2 border-border-strong relative group">
                                    {formState.avatarUrl ? (
                                        <img src={formState.avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="flex items-center justify-center w-full h-full text-text-secondary">No Avatar</div>
                                    )}
                                    <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center space-x-2">
                                        <button type="button" onClick={() => avatarInputRef.current?.click()} className="p-2 text-white hover:bg-white/20 rounded-full" title="Upload"><UploadIcon className="w-5 h-5"/></button>
                                        <button type="button" onClick={handleGenerateAvatar} disabled={isGeneratingAvatar} className="p-2 text-white hover:bg-white/20 rounded-full" title="Generate">{isGeneratingAvatar ? <SpinnerIcon className="w-5 h-5 animate-spin"/> : <ImageIcon className="w-5 h-5"/>}</button>
                                    </div>
                                </div>
                                <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
                                <input 
                                    type="text" 
                                    placeholder="Character Name" 
                                    className="w-full bg-background-secondary border border-border-strong rounded px-3 py-2 text-text-primary text-center font-bold"
                                    value={formState.name}
                                    onChange={e => handleChange('name', e.target.value)}
                                    required
                                />
                                <select 
                                    value={formState.characterType || 'character'} 
                                    onChange={e => handleChange('characterType', e.target.value)}
                                    className="w-full bg-background-secondary border border-border-strong rounded px-3 py-2 text-text-primary text-sm"
                                >
                                    <option value="character">Persona (Character)</option>
                                    <option value="narrator">Scenario (Narrator)</option>
                                </select>
                            </div>
                            <div className="col-span-1 md:col-span-2 space-y-4">
                                <div className="relative">
                                    <label className="block text-sm font-medium text-text-secondary mb-1">Description</label>
                                    <textarea 
                                        className="w-full bg-background-secondary border border-border-strong rounded px-3 py-2 text-text-primary h-24 resize-none"
                                        value={formState.description}
                                        onChange={e => handleChange('description', e.target.value)}
                                        placeholder="Short description of the character..."
                                    />
                                    {renderAIGenButton('description', "Write a short, engaging description for a character named {{name}}.", "Auto-generate Description")}
                                </div>
                                <div className="relative">
                                    <label className="block text-sm font-medium text-text-secondary mb-1">First Message</label>
                                    <textarea 
                                        className="w-full bg-background-secondary border border-border-strong rounded px-3 py-2 text-text-primary h-32"
                                        value={formState.firstMessage}
                                        onChange={e => handleChange('firstMessage', e.target.value)}
                                        placeholder="Greeting message sent when a new chat starts..."
                                    />
                                    {renderAIGenButton('firstMessage', "Write an engaging first message for a roleplay character named {{name}} described as: {{desc}}. Use {{user}} to refer to the user.", "Auto-generate First Message")}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* --- DETAILS TAB --- */}
                    {activeTab === 'details' && (
                        <div className="space-y-6 animate-fadeIn">
                            <div className="relative">
                                <label className="block text-sm font-medium text-text-secondary mb-1">Personality / Role Instruction</label>
                                <textarea 
                                    className="w-full bg-background-secondary border border-border-strong rounded px-3 py-2 text-text-primary h-48"
                                    value={formState.personality}
                                    onChange={e => handleChange('personality', e.target.value)}
                                    placeholder="Detailed personality instructions, behavior guidelines, and traits..."
                                />
                                {renderAIGenButton('personality', "Write detailed personality and roleplay instructions for {{name}}, described as: {{desc}}.", "Auto-generate Personality")}
                            </div>

                            <div className="relative">
                                <label className="block text-sm font-medium text-text-secondary mb-1">Backstory</label>
                                <textarea 
                                    className="w-full bg-background-secondary border border-border-strong rounded px-3 py-2 text-text-primary h-40"
                                    value={formState.backstory}
                                    onChange={e => handleChange('backstory', e.target.value)}
                                    placeholder="The character's history, origin, and key life events..."
                                />
                                {renderAIGenButton('backstory', "Write a compelling backstory for {{name}}, described as: {{desc}}.", "Auto-generate Backstory")}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-text-secondary mb-1">Physical Appearance</label>
                                    <textarea 
                                        className="w-full bg-background-primary border border-border-strong rounded px-3 py-2 text-text-primary h-20"
                                        value={formState.physicalAppearance}
                                        onChange={e => handleChange('physicalAppearance', e.target.value)}
                                        placeholder="Eye color, hair style, clothing, etc."
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-text-secondary mb-1">Personality Traits (comma-separated)</label>
                                    <textarea 
                                        className="w-full bg-background-primary border border-border-strong rounded px-3 py-2 text-text-primary h-20"
                                        value={formState.personalityTraits}
                                        onChange={e => handleChange('personalityTraits', e.target.value)}
                                        placeholder="e.g. Brave, Stubborn, Intelligent..."
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    {/* --- ADVANCED LOGIC TAB --- */}
                    {activeTab === 'advanced' && (
                        <div className="space-y-6 animate-fadeIn">
                            <div className="bg-background-secondary p-4 rounded-lg border border-border-neutral">
                                <h3 className="text-lg font-medium text-text-primary mb-4 flex items-center">
                                    <SparklesIcon className="w-5 h-5 mr-2 text-accent-yellow"/> Deep Thinking & Grounding
                                </h3>

                                <div className="space-y-4">
                                    <div className="flex items-center justify-between">
                                        <div>
                                            <span className="text-sm font-medium text-text-primary block">Thinking Budget (Deep Thinking)</span>
                                            <span className="text-xs text-text-secondary">Allows the model to reason before responding (Gemini 2.5/3.0 only). 0 to disable.</span>
                                        </div>
                                        <input 
                                            type="number" 
                                            value={formState.thinkingBudget || 0}
                                            onChange={e => handleChange('thinkingBudget', parseInt(e.target.value) || 0)}
                                            className="w-24 bg-background-primary border border-border-strong rounded px-2 py-1 text-text-primary"
                                            min="0"
                                            max="32000"
                                            step="1024"
                                        />
                                    </div>

                                    <div className="flex items-center space-x-3">
                                        <input 
                                            type="checkbox" 
                                            id="useSearch"
                                            checked={formState.useSearchGrounding || false} 
                                            onChange={e => handleChange('useSearchGrounding', e.target.checked)}
                                            className="rounded border-border-strong bg-background-primary text-primary-600 focus:ring-primary-500 h-5 w-5"
                                        />
                                        <div>
                                            <label htmlFor="useSearch" className="text-sm font-medium text-text-primary block">Enable Google Search Grounding</label>
                                            <span className="text-xs text-text-secondary">Allows the character to access real-time information from the web.</span>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="bg-background-secondary p-4 rounded-lg border border-border-neutral space-y-4">
                                <h3 className="text-lg font-medium text-text-primary flex items-center">
                                    <VaultIcon className="w-5 h-5 mr-2 text-text-secondary" /> Vault Attachments
                                </h3>
                                <p className="text-sm text-text-secondary">
                                    Grant this character access to specific files from your Secure Vault. The content of these files will be visible to the character during chats.
                                </p>

                                <div className="space-y-2">
                                    {(formState.vaultAttachmentIds || []).map(id => (
                                        <div key={id} className="flex items-center justify-between p-2 bg-background-primary rounded border border-border-neutral">
                                            <span className="text-sm text-text-primary font-mono text-xs truncate max-w-[200px]">{id}</span>
                                            <button 
                                                type="button" 
                                                onClick={() => handleRemoveVaultItem(id)}
                                                className="text-accent-red hover:text-red-400"
                                                title="Remove Access"
                                            >
                                                <TrashIcon className="w-4 h-4"/>
                                            </button>
                                        </div>
                                    ))}
                                    {(formState.vaultAttachmentIds?.length === 0) && <p className="text-sm text-text-secondary italic">No vault items attached.</p>}

                                    <button 
                                        type="button" 
                                        onClick={handleAttachVaultItems}
                                        className="w-full flex items-center justify-center space-x-2 py-2 border border-dashed border-border-strong rounded text-text-secondary hover:text-text-primary hover:bg-background-tertiary"
                                    >
                                        <PlusIcon className="w-4 h-4" /> <span>Attach from Vault</span>
                                    </button>
                                </div>
                            </div>

                            <div className="bg-background-secondary p-4 rounded-lg border border-border-neutral space-y-4">
                                <div className="flex items-center justify-between">
                                    <h3 className="text-lg font-medium text-text-primary">Knowledge Base (RAG)</h3>
                                    <label className="flex items-center space-x-2 cursor-pointer">
                                        <input 
                                            type="checkbox" 
                                            checked={formState.ragEnabled} 
                                            onChange={e => handleChange('ragEnabled', e.target.checked)}
                                            className="rounded border-border-strong bg-background-primary text-primary-600 focus:ring-primary-500"
                                        />
                                        <span className="text-sm text-text-primary">Enable RAG</span>
                                    </label>
                                </div>

                                {formState.ragEnabled && (
                                    <div className="space-y-4">
                                        <div className="border border-dashed border-border-strong rounded-lg p-6 flex flex-col items-center justify-center bg-background-primary">
                                            <input 
                                                type="file" 
                                                ref={ragFileInputRef} 
                                                className="hidden" 
                                                onChange={handleRagFileUpload} 
                                                accept=".txt,.md,.json"
                                            />
                                            <button 
                                                type="button"
                                                onClick={() => ragFileInputRef.current?.click()}
                                                className="flex items-center space-x-2 text-primary-500 hover:text-primary-400"
                                            >
                                                <PlusIcon className="w-6 h-6" />
                                                <span className="font-medium">Upload Knowledge File</span>
                                            </button>
                                            <p className="text-xs text-text-secondary mt-2">Supported: .txt, .md, .json</p>
                                        </div>

                                        {indexingStatus && (
                                            <div className="text-sm text-center text-primary-500 animate-pulse font-medium">
                                                {indexingStatus}
                                            </div>
                                        )}

                                        {formState.ragSources && formState.ragSources.length > 0 && (
                                            <div className="space-y-2">
                                                <h4 className="text-sm font-medium text-text-secondary">Indexed Files:</h4>
                                                {formState.ragSources.map(source => (
                                                    <div key={source.id} className="flex items-center justify-between p-2 bg-background-primary rounded border border-border-neutral">
                                                        <span className="text-sm text-text-primary truncate">{source.fileName}</span>
                                                        <button 
                                                            type="button"
                                                            onClick={() => onDeleteRagSource(formState.id, source.id)}
                                                            className="text-accent-red hover:text-red-400 p-1"
                                                        >
                                                            <TrashIcon className="w-4 h-4" />
                                                        </button>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {/* --- MEMORY & INTELLIGENCE TAB --- */}
                    {activeTab === 'memory' && (
                        <div className="space-y-6 animate-fadeIn">
                            <div className="bg-background-secondary p-4 rounded-lg border border-border-neutral">
                                <h3 className="text-lg font-medium text-text-primary mb-2 flex items-center">
                                    <CogIcon className="w-5 h-5 mr-2 text-text-secondary" /> Context & Memory Manager
                                </h3>
                                <p className="text-sm text-text-secondary mb-4">
                                    Configure a separate LLM for memory summarization, context extraction, and "AI Assist" features. 
                                    This allows you to use a faster/cheaper model (like Flash) for maintenance tasks, keeping your main interaction model (like Pro) focused on roleplay.
                                </p>

                                <div className="space-y-4 border-t border-border-neutral pt-4">
                                    <div>
                                        <label className="block text-sm font-medium text-text-primary mb-1">Service Provider</label>
                                        <select 
                                            value={formState.summaryApiConfig?.service || 'default'}
                                            onChange={e => handleNestedChange('summaryApiConfig', 'service', e.target.value)}
                                            className="w-full bg-background-primary border border-border-strong rounded px-3 py-2 text-text-primary"
                                        >
                                            <option value="default">Same as Character (Default)</option>
                                            <option value="gemini">Google Gemini</option>
                                            <option value="openai">OpenAI Compatible</option>
                                        </select>
                                    </div>

                                    {(formState.summaryApiConfig?.service === 'gemini' || formState.summaryApiConfig?.service === 'openai') && (
                                        <>
                                            <div>
                                                <label className="block text-sm font-medium text-text-primary mb-1">API Key</label>
                                                <input 
                                                    type="password"
                                                    value={formState.summaryApiConfig?.apiKey || ''}
                                                    onChange={e => handleNestedChange('summaryApiConfig', 'apiKey', e.target.value)}
                                                    placeholder="API Key"
                                                    className="w-full bg-background-primary border border-border-strong rounded px-3 py-2 text-text-primary"
                                                />
                                            </div>
                                            <div>
                                                <label className="block text-sm font-medium text-text-primary mb-1">Model ID</label>
                                                <input 
                                                    type="text"
                                                    value={formState.summaryApiConfig?.model || ''}
                                                    onChange={e => handleNestedChange('summaryApiConfig', 'model', e.target.value)}
                                                    placeholder="e.g. gemini-2.5-flash-latest"
                                                    className="w-full bg-background-primary border border-border-strong rounded px-3 py-2 text-text-primary"
                                                />
                                            </div>
                                            {formState.summaryApiConfig?.service === 'openai' && (
                                                <div>
                                                    <label className="block text-sm font-medium text-text-primary mb-1">API Endpoint</label>
                                                    <input 
                                                        type="text"
                                                        value={formState.summaryApiConfig?.apiEndpoint || ''}
                                                        onChange={e => handleNestedChange('summaryApiConfig', 'apiEndpoint', e.target.value)}
                                                        placeholder="e.g. https://api.openai.com/v1/chat/completions"
                                                        className="w-full bg-background-primary border border-border-strong rounded px-3 py-2 text-text-primary"
                                                    />
                                                </div>
                                            )}
                                        </>
                                    )}
                                </div>
                            </div>

                            <div className="bg-background-secondary p-4 rounded-lg border border-border-neutral">
