type ActivePanel = 'chats' | 'characters' | 'lorebooks' | 'none';
type ActiveView = 'chat' | 'character-form' | 'plugins' | 'lorebooks';

export const MainLayout: React.FC = () => {
    const [appData, setAppData] = useState<AppData>({ characters: [], chatSessions: [], plugins: [], lorebooks: [] });

    const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
    const [editingCharacter, setEditingCharacter] = useState<Character | null>(null);

    const [activeView, setActiveView] = useState<ActiveView>('chat');
    const [activePanel, setActivePanel] = useState<ActivePanel>('chats');

    const [isLogViewerVisible, setIsLogViewerVisible] = useState(false);
    const [isHelpVisible, setIsHelpVisible] = useState(false);
    const [isChatModalVisible, setIsChatModalVisible] = useState(false);
    const [isAppearanceModalVisible, setIsAppearanceModalVisible] = useState(false);

    // Vault State Management
    const [isVaultVisible, setIsVaultVisible] = useState(false);
    const [vaultMode, setVaultMode] = useState<'manage' | 'select'>('manage');
    const [vaultSelectionCallback, setVaultSelectionCallback] = useState<((ids: string[]) => void) | null>(null);

    const [confirmationRequest, setConfirmationRequest] = useState<ConfirmationRequest | null>(null);

    const [showArchivedChats, setShowArchivedChats] = useState(false);
    const [showArchivedCharacters, setShowArchivedCharacters] = useState(false);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const sandboxes = useRef(new Map<string, PluginSandbox>()).current;

    const persistData = useCallback(async (data: AppData) => {
        await saveData(data);
    }, []);

    const handlePanelToggle = (panel: ActivePanel) => {
        setActivePanel(prev => (prev === panel ? 'none' : panel));
    };

    // Secure handler for API requests coming from plugin sandboxes
    const handlePluginApiRequest = useCallback(async (request: GeminiApiRequest) => {
        switch (request.type) {
            case 'generateContent':
                return await geminiService.generateContent(request.prompt);
            case 'generateImage':
                // The image generation plugin now has its own complete settings object.
                // We pass this directly to the service.
                const imagePlugin = appData.plugins?.find(p => p.id === 'default-image-generator');
                const settings = { ...imagePlugin?.settings, ...request.settings };
                return await geminiService.generateImageFromPrompt(request.prompt, settings);
            default:
                throw new Error('Unknown API request type from plugin.');
        }
    }, [appData.plugins]);

    useEffect(() => {
        const loadInitialData = async () => {
            logger.log("Loading initial application data...");
            try {
                const data = await loadData();
                let dataNeedsSave = false;

                // --- Key Generation and Migration ---
                if (!data.userKeys) {
                    logger.log("User signing keys not found. Generating new master key pair.");
                    const keyPair = await cryptoService.generateSigningKeyPair();
                    data.userKeys = {
                        publicKey: await cryptoService.exportKey(keyPair.publicKey),
                        privateKey: await cryptoService.exportKey(keyPair.privateKey),
                    };
                    dataNeedsSave = true;
                    logger.log("New user master key pair generated.");
                }

                // --- UI Settings Migration (from global to per-chat) ---
                const dataAsAny = data as any;
                if (dataAsAny.uiSettings && Object.keys(dataAsAny.uiSettings).length > 0) {
                    logger.log("Migrating global UI settings to chat sessions...");
                    const globalSettings = dataAsAny.uiSettings;
                    delete dataAsAny.uiSettings;

                    data.chatSessions = data.chatSessions.map(cs => {
                        if (!cs.uiSettings) {
                            return { ...cs, uiSettings: globalSettings };
                        }
                        return cs;
                    });

                    logger.log(`Applied global UI settings to relevant chat sessions.`);
                    dataNeedsSave = true;
                }

                const defaultPlugins = [defaultImagePlugin, defaultTtsPlugin];
                if (!data.plugins) data.plugins = [];

                defaultPlugins.forEach(defaultPlugin => {
                    let hasPlugin = data.plugins!.some(p => p.id === defaultPlugin.id);
                    if (!hasPlugin) {
                        data.plugins!.push(defaultPlugin);
                        logger.log(`Default plugin injected: ${defaultPlugin.name}`);
                        dataNeedsSave = true;
                    } else {
                        // Ensure settings exist on existing default plugins
                        data.plugins = data.plugins!.map(p => {
                            if (p.id === defaultPlugin.id && !p.settings) {
                                dataNeedsSave = true;
                                return { ...p, settings: defaultPlugin.settings };
                            }
                            return p;
                        });
                    }
                });


                if (dataNeedsSave) {
                    await persistData(data);
                    logger.log("Initial data modifications saved.");
                }

                setAppData(data);
                if (data.chatSessions.length > 0) {
                    setSelectedChatId(data.chatSessions.find(cs => !cs.isArchived)?.id || data.chatSessions[0].id);
                    setActiveView('chat');
                } else {
                    if (data.characters.length > 0) {
                        setActivePanel('characters');
                    }
                }
                logger.log("Application data loaded successfully.", { characters: data.characters.length, sessions: data.chatSessions.length, plugins: data.plugins.length, lorebooks: data.lorebooks?.length || 0 });
            } catch (error) {
                logger.error("Failed to load initial data. Data might be corrupt or key is invalid.", error);
                alert("Critical error loading data. Please check logs. You may need to clear your site data if the database is corrupt.");
            }
        };
        loadInitialData();

        return () => {
            sandboxes.forEach(sandbox => sandbox.terminate());
            sandboxes.clear();
        };
    }, [persistData]);

    useEffect(() => {
        appData.plugins?.forEach(async (plugin) => {
            const existingSandbox = sandboxes.get(plugin.id);
            if (plugin.enabled && !existingSandbox) {
                try {
                    logger.log(`Initializing sandbox for plugin: ${plugin.name}`);
                    const sandbox = new PluginSandbox(handlePluginApiRequest);
                    await sandbox.loadCode(plugin.code);
                    sandboxes.set(plugin.id, sandbox);
                } catch (error) {
                    logger.error(`Failed to load plugin "${plugin.name}":`, error);
                    alert(`Error loading plugin "${plugin.name}". Check logs for details.`);
                }
            } else if (!plugin.enabled && existingSandbox) {
                logger.log(`Terminating sandbox for disabled plugin: ${plugin.name}`);
                existingSandbox.terminate();
                sandboxes.delete(plugin.id);
            }
        });
        sandboxes.forEach((_, id) => {
            if (!appData.plugins?.some(p => p.id === id)) {
                logger.log(`Pruning sandbox for deleted plugin ID: ${id}`);
                sandboxes.get(id)?.terminate();
                sandboxes.delete(id);
            }
        });

    }, [appData.plugins, sandboxes, handlePluginApiRequest]);

    const handleSaveCharacter = async (character: Character) => {
        const isNew = !appData.characters.some(c => c.id === character.id);
        let updatedCharacter = { ...character };

        if (isNew || !updatedCharacter.keys) {
            logger.log(`Generating signing keys for character: ${updatedCharacter.name}`);
            const keyPair = await cryptoService.generateSigningKeyPair();
            updatedCharacter.keys = {
                publicKey: await cryptoService.exportKey(keyPair.publicKey),
                privateKey: await cryptoService.exportKey(keyPair.privateKey),
            };
        }

        if (appData.userKeys) {
            logger.log("Signing character data with user's master key...");
            const userPrivateKey = await cryptoService.importKey(appData.userKeys.privateKey, 'sign');

            const dataToSign: Partial<Character> = { ...updatedCharacter };
            delete dataToSign.signature; 

            const canonicalString = cryptoService.createCanonicalString(dataToSign);
            updatedCharacter.signature = await cryptoService.sign(canonicalString, userPrivateKey);
            updatedCharacter.userPublicKeyJwk = appData.userKeys.publicKey;
            logger.log("Character data signed successfully.");
        }

        const updatedCharacters = isNew 
            ? [...appData.characters, updatedCharacter] 
            : appData.characters.map(c => c.id === updatedCharacter.id ? updatedCharacter : c);

        const updatedData = { ...appData, characters: updatedCharacters };
        setAppData(updatedData);
        await persistData(updatedData);
        logger.log(`Character ${isNew ? 'created' : 'updated'}: ${updatedCharacter.name}`);

        if (editingCharacter && editingCharacter.id === updatedCharacter.id) {
            setEditingCharacter(updatedCharacter);
        }

        setActiveView('chat');
        if (isNew) {
           setEditingCharacter(null);
        }
    };

    const handleCharacterUpdate = useCallback((character: Character) => {
        setAppData(prevAppData => {
            const updatedCharacters = prevAppData.characters.map(c => c.id === character.id ? character : c);
            const updatedData = { ...prevAppData, characters: updatedCharacters };
            persistData(updatedData);
            logger.log(`Character data updated programmatically: ${character.name}`);
            return updatedData;
        });
    }, [persistData]);

    const handleArchiveCharacter = (characterId: string) => {
        const characterName = appData.characters.find(c => c.id === characterId)?.name || 'Unknown';
        setConfirmationRequest({
            message: (
                <span>Are you sure you want to archive <strong>{characterName}</strong>? They will be hidden from the list but can be restored later.</span>
            ),
            onConfirm: () => {
                const updatedCharacters = appData.characters.map(c => 
                    c.id === characterId ? { ...c, isArchived: true } : c
                );

                const updatedData = { ...appData, characters: updatedCharacters };
                setAppData(updatedData);
                persistData(updatedData);
                logger.log(`Archived character: ${characterName}`);
                setConfirmationRequest(null);
            },
            onCancel: () => setConfirmationRequest(null)
        });
    };

    const handleRestoreCharacter = (characterId: string) => {
        const updatedCharacters = appData.characters.map(c => 
            c.id === characterId ? { ...c, isArchived: false } : c
        );
        const updatedData = { ...appData, characters: updatedCharacters };
        setAppData(updatedData);
        persistData(updatedData);
        logger.log(`Restored character: ${appData.characters.find(c => c.id === characterId)?.name}`);
    };

    const handlePermanentlyDeleteCharacter = (characterId: string) => {
        const characterName = appData.characters.find(c => c.id === characterId)?.name || 'Unknown';
        setConfirmationRequest({
            message: (
                <span>Are you sure you want to permanently delete <strong>{characterName}</strong>? All chats involving this character and all associated knowledge files will also be permanently deleted. This action cannot be undone.</span>
            ),
            onConfirm: () => {
                const characterToDelete = appData.characters.find(c => c.id === characterId);

                if (characterToDelete?.ragSources && characterToDelete.ragSources.length > 0) {
                    characterToDelete.ragSources.forEach(async (source) => {
                        await ragService.deleteSource(source.id);
                    });
                    logger.log(`Deleted all knowledge sources for character: ${characterName}`);
                }

                const updatedCharacters = appData.characters.filter(c => c.id !== characterId);
                const updatedSessions = appData.chatSessions.filter(s => !s.characterIds.includes(characterId));

                const updatedData = { ...appData, characters: updatedCharacters, chatSessions: updatedSessions };
                setAppData(updatedData);
                persistData(updatedData);
                logger.log(`Permanently deleted character and associated sessions: ${characterName}`);

                if (selectedChatId && !updatedSessions.some(s => s.id === selectedChatId)) {
                    setSelectedChatId(updatedSessions.length > 0 ? updatedSessions[0].id : null);
                }
                setConfirmationRequest(null);
            },
            onCancel: () => setConfirmationRequest(null)
        });
    };

    const handleDeleteRagSource = async (characterId: string, sourceId: string) => {
        const character = appData.characters.find(c => c.id === characterId);
        if (!character) return;
        const source = character.ragSources?.find(s => s.id === sourceId);
        if (!source) return;

        setConfirmationRequest({
            message: `Are you sure you want to delete the knowledge file "${source.fileName}"? This cannot be undone.`,
            onConfirm: async () => {
                try {
                    await ragService.deleteSource(sourceId);
                    const updatedCharacter = {
                        ...character,
                        ragSources: character.ragSources?.filter(s => s.id !== sourceId)
                    };
                    await handleSaveCharacter(updatedCharacter);
                    logger.log(`Deleted RAG source "${source.fileName}" for character ${character.name}`);
                } catch (error) {
                    logger.error("Failed to delete RAG source:", error);
                    alert(`Failed to delete knowledge source. Check logs for details.`);
                } finally {
                    setConfirmationRequest(null);
                }
            },
            onCancel: () => setConfirmationRequest(null)
        });
    };

    const handleCreateChat = (name: string, characterIds: string[], lorebookIds: string[]) => {
        const messages: Message[] = [];
        if (characterIds.length === 1) {
            const character = appData.characters.find(c => c.id === characterIds[0]);
            if (character && character.firstMessage) {
                messages.push({
                    role: 'model',
                    content: character.firstMessage.replace(/{{user}}/g, 'You'),
                    timestamp: new Date().toISOString(),
                    characterId: character.id
                });
            }
        }

        const newSession: ChatSession = {
            id: crypto.randomUUID(),
            name,
            characterIds,
            messages,
            uiSettings: {},
            lorebookIds,
        };
        const updatedSessions = [...appData.chatSessions, newSession];
        const updatedData = { ...appData, chatSessions: updatedSessions };
        setAppData(updatedData);
        persistData(updatedData);
        setSelectedChatId(newSession.id);
        setActiveView('chat');
        setIsChatModalVisible(false);
        logger.log(`New chat created: "${name}"`);
        setActivePanel('none');
    };

    const handleArchiveChat = (sessionId: string) => {
        const sessionName = appData.chatSessions.find(s => s.id === sessionId)?.name || 'Unknown Chat';
        setConfirmationRequest({
            message: `Are you sure you want to archive the chat session "${sessionName}"? It can be restored later.`,
            onConfirm: () => {
                const updatedSessions = appData.chatSessions.map(s => 
                    s.id === sessionId ? { ...s, isArchived: true } : s
                );
                const updatedData = { ...appData, chatSessions: updatedSessions };
                setAppData(updatedData);
                persistData(updatedData);
                if (selectedChatId === sessionId) {
                    setSelectedChatId(updatedSessions.find(s => !s.isArchived)?.id || null);
                }
                logger.log(`Chat session archived: ${sessionId}`);
                setConfirmationRequest(null);
            },
            onCancel: () => setConfirmationRequest(null)
        });
    };

    const handleRestoreChat = (sessionId: string) => {
        const updatedSessions = appData.chatSessions.map(s => 
            s.id === sessionId ? { ...s, isArchived: false } : s
        );
        const updatedData = { ...appData, chatSessions: updatedSessions };
        setAppData(updatedData);
        persistData(updatedData);
        logger.log(`Restored chat: ${appData.chatSessions.find(s => s.id === sessionId)?.name}`);
    };

    const handlePermanentlyDeleteChat = (sessionId: string) => {
        const sessionName = appData.chatSessions.find(s => s.id === sessionId)?.name || 'Unknown Chat';
        setConfirmationRequest({
            message: `Are you sure you want to permanently delete the chat session "${sessionName}"? This action cannot be undone.`,
            onConfirm: () => {
                const updatedSessions = appData.chatSessions.filter(s => s.id !== sessionId);
                const updatedData = { ...appData, chatSessions: updatedSessions };
                setAppData(updatedData);
                persistData(updatedData);
                if (selectedChatId === sessionId) {
                    setSelectedChatId(updatedSessions.length > 0 ? updatedSessions[0].id : null);
                }
                logger.log(`Chat session permanently deleted: ${sessionId}`);
                setConfirmationRequest(null);
            },
            onCancel: () => setConfirmationRequest(null)
        });
    };

    const handleEditCharacter = (character: Character) => {
        setEditingCharacter(character);
        setActiveView('character-form');
        setActivePanel('none');
    };

    const handleAddNewCharacter = () => {
        setEditingCharacter(null);
        setActiveView('character-form');
        setActivePanel('none');
    };

    const handleSelectChat = (sessionId: string) => {
        setSelectedChatId(sessionId);
        setActiveView('chat');
        setEditingCharacter(null);
        setActivePanel('none');
    };

    const handleSessionUpdate = useCallback((session: ChatSession) => {
        setAppData(prevAppData => {
            const sessionExists = prevAppData.chatSessions.some(s => s.id === session.id);
            const updatedSessions = sessionExists
                ? prevAppData.chatSessions.map(s => s.id === session.id ? session : s)
                : [...prevAppData.chatSessions, session];

            const updatedData = { ...prevAppData, chatSessions: updatedSessions };
            persistData(updatedData);
            return updatedData;
        });
    }, [persistData]);

    const triggerDownload = (filename: string, data: object) => {
        const jsonString = JSON.stringify(data, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleSaveBackup = useCallback(async () => {
        try {
            const dataToExport = {
                spec: 'ai_nexus_backup',
                version: '1.0',
                data: appData
            };
            const timestamp = new Date().toISOString().split('T')[0];
            const filename = `ai-nexus-backup-${timestamp}.json`;
            triggerDownload(filename, dataToExport);
            logger.log("Full backup saved successfully.", { filename });
        } catch (error) {
            logger.error("Failed to save backup.", error);
            alert("Failed to save backup. Check logs for details.");
        }
    }, [appData]);

    const handleExportCharacter = async (characterId: string) => {
        const character = appData.characters.find(c => c.id === characterId);
        if (character) {
            try {
                const card = await compatibilityService.nexusToV2(character);
                const filename = `${character.name.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`;
                triggerDownload(filename, card);
                logger.log(`Exported character: ${character.name}`, { filename });
            } catch (error) {
                logger.error(`Failed to export character: ${character.name}`, error);
                alert(`Failed to export character. Check logs. Error: ${error instanceof Error ? error.message : String(error)}`);
            }
        }
    };

    const handleExportChat = (sessionId: string) => {
        const session = appData.chatSessions.find(s => s.id === sessionId);
        if (session) {
            const filename = `${session.name.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_chat.json`;
            triggerDownload(filename, session);
            logger.log(`Exported chat: ${session.name}`, { filename });
        }
    };

    const handleImportData = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        logger.log(`Starting data import from file: ${file.name}`);
        const reader = new FileReader();

        const cleanup = () => {
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
            }
        };

        reader.onerror = () => {
            logger.error("FileReader failed to read the file.", reader.error);
            alert("An error occurred while trying to read the file: " + (reader.error?.message || "Unknown error"));
            cleanup();
        };

        reader.onabort = () => {
            logger.warn("File reading aborted.");
            cleanup();
        }

        reader.onload = async (e) => {
            logger.log("File has been loaded into memory. Processing content...");
            try {
                const text = e.target?.result as string;
                if (!text) throw new Error("File content is empty.");

                let data;
                try {
                    data = JSON.parse(text);
                } catch (parseError) {
                    throw new Error("Invalid JSON file format.");
                }

                const isValidAppData = (d: any): d is AppData => {
                    return typeof d === 'object' && d !== null &&
                    Array.isArray(d.characters) &&
                    Array.isArray(d.chatSessions);
                };

                // --- Type Identification Logic ---

                // 1. AI Nexus Backup (v1.0+)
                if (data.spec === 'ai_nexus_backup' && isValidAppData(data.data)) {
                    logger.log("Detected valid AI Nexus full backup format.");
                    setConfirmationRequest({
                        message: 'This is a full backup file. Importing it will overwrite all current data. Are you sure?',
                        onConfirm: async () => {
                            await persistData(data.data);
                            alert('Backup restored successfully! The application will now reload.');
                            setConfirmationRequest(null);
                            window.location.reload();
                        },
                        onCancel: () => setConfirmationRequest(null)
                    });
                    return;
                }

                // 2. SillyTavern World Info (Lorebook)
                const importedLorebook = compatibilityService.sillyTavernWorldInfoToNexus(data, file.name);
                if (importedLorebook) {
                    const newLorebook: Lorebook = {
                        ...importedLorebook,
                        id: crypto.randomUUID(),
                    };
                    const updatedData = { ...appData, lorebooks: [...(appData.lorebooks || []), newLorebook] };
                    setAppData(updatedData);
                    await persistData(updatedData);
                    logger.log(`Imported Lorebook: ${newLorebook.name}`);
                    alert(`Lorebook "${newLorebook.name}" imported successfully.`);
                    return;
                }

                // 3. Character Card (V2 compatible or Nexus-exported)
                const importResult = compatibilityService.v2ToNexus(data);
                if (importResult) {
                    logger.log("Detected Character Card format.");
                    const { character, lorebook } = importResult;

                    let updatedCharacters = [...appData.characters, character];
                    let updatedLorebooks = appData.lorebooks || [];
                    let alertMessage = `Character "${character.name}" imported successfully.`;

                    if (lorebook) {
                        updatedLorebooks = [...updatedLorebooks, lorebook];
                        alertMessage += ` A new Lorebook "${lorebook.name}" was also created.`;
                    }

                    const updatedData = { ...appData, characters: updatedCharacters, lorebooks: updatedLorebooks };
                    setAppData(updatedData);
                    await persistData(updatedData);

                    logger.log(`Imported character: ${character.name}${lorebook ? ' with auto-generated lorebook' : ''}`);
                    alert(alertMessage);
                    return;
                }

                // 4. Legacy Backup (checked after specific formats)
                // Also check for 'characters' key specifically to be lenient with legacy exports
                if (isValidAppData(data)) {
                    logger.log("Detected legacy backup format.");
                    setConfirmationRequest({
                        message: 'This appears to be a full backup. Importing it will overwrite all current data. Are you sure?',
                        onConfirm: async () => {
                             await persistData(data);
                             alert('Backup restored successfully! The application will now reload.');
                             setConfirmationRequest(null);
                             window.location.reload();
                        },
                        onCancel: () => setConfirmationRequest(null)
                    });
                    return;
                }

                // 5. Chat Session
                if (data.id && Array.isArray(data.messages) && Array.isArray(data.characterIds)) {
                    logger.log("Detected Chat Session format.");
                    const newSession: ChatSession = { ...data, id: crypto.randomUUID() };
                    const updatedData = { ...appData, chatSessions: [...appData.chatSessions, newSession] };
                    setAppData(updatedData);
                    await persistData(updatedData);
                    logger.log(`Imported chat session: ${newSession.name}`);
                    alert(`Chat "${newSession.name}" imported successfully.`);
                    return;
                }

                // Diagnostic logging for failure
                logger.error("File recognition failed. Keys present:", Object.keys(data));
                throw new Error("Unrecognized file format. Not a valid character, lorebook, chat, or backup file. See logs for debug info.");

            } catch (error) {
                logger.error("Import failed during processing:", error);
                alert(`Failed to import data. Error: ${error instanceof Error ? error.message : String(error)}`);
            } finally {
                cleanup();
            }
        };

        reader.readAsText(file);
    };

    const handlePluginsUpdate = (updatedPlugins: Plugin[]) => {
        const updatedData = { ...appData, plugins: updatedPlugins };
        setAppData(updatedData);
        persistData(updatedData);
    };

    const handleLorebooksUpdate = (updatedLorebooks: Lorebook[]) => {
        const updatedData = { ...appData, lorebooks: updatedLorebooks };
        setAppData(updatedData);
        persistData(updatedData);
    };

    const handleMemoryImport = (fromSessionId: string, toSessionId: string) => {
        const fromSession = appData.chatSessions.find(s => s.id === fromSessionId);
        const toSession = appData.chatSessions.find(s => s.id === toSessionId);

        if (!fromSession || !toSession) {
            logger.error("Could not find sessions for memory import.");
            return;
        }

        const toSessionParticipants = appData.characters.filter(c => toSession.characterIds.includes(c.id));
        let charactersToUpdate: Character[] = [];
        let memoriesImported = false;

        toSessionParticipants.forEach(toChar => {
            if (fromSession.characterIds.includes(toChar.id)) {
                const fromChar = appData.characters.find(c => c.id === toChar.id);
                if (fromChar && fromChar.memory && fromChar.memory.trim() !== 'No memories yet.') {
                    const updatedMemory = `${toChar.memory || ''}\n\n[Imported memory from chat "${fromSession.name}"]:\n${fromChar.memory}`;
                    charactersToUpdate.push({ ...toChar, memory: updatedMemory.trim() });
                    memoriesImported = true;
                }
            }
        });

        if (!memoriesImported) {
             alert(`No shared characters with memories found in "${fromSession.name}".`);
             return;
        }

        const updatedCharacters = appData.characters.map(c => {
            const updated = charactersToUpdate.find(uc => uc.id === c.id);
            return updated || c;
        });

        const narratorMessage: Message = {
            role: 'narrator',
            content: `Memory from "${fromSession.name}" has been integrated.`,
            timestamp: new Date().toISOString()
        };
        const updatedSession = {...toSession, messages: [...toSession.messages, narratorMessage] };
        const updatedSessions = appData.chatSessions.map(s => s.id === toSessionId ? updatedSession : s);

        const updatedData = { ...appData, characters: updatedCharacters, chatSessions: updatedSessions };
        setAppData(updatedData);
        persistData(updatedData);

        logger.log(`Memory imported from session "${fromSession.name}" to "${toSession.name}"`);
    };

    const triggerPluginHook = useCallback(async <T, R,>(hookName: string, data: T): Promise<R> => {
        let processedData: any = data;
        const enabledPlugins = appData.plugins?.filter(p => p.enabled) || [];

        if (hookName === 'generateImage') {
            const imagePlugin = appData.plugins?.find(p => p.id === 'default-image-generator');
            processedData = { ...processedData, settings: imagePlugin?.settings || {} };
        }

        for (const plugin of enabledPlugins) {
            const sandbox = sandboxes.get(plugin.id);
            if (sandbox) {
                try {
                    processedData = await sandbox.executeHook(hookName, processedData);
                } catch (error) {
                    logger.error(`Error in plugin '${plugin.name}' during hook '${hookName}':`, error);
                }
            }
        }
        return processedData as R;
    }, [appData.plugins, sandboxes]);

    const handleGenerateImage = useCallback(async (prompt: string): Promise<string | null> => {
        try {
            const imagePlugin = appData.plugins?.find(p => p.id === 'default-image-generator');
            if (!imagePlugin) {
                throw new Error("Image generation plugin not found.");
            }
            logger.log("Generating image with prompt:", prompt);
            const imageUrl = await geminiService.generateImageFromPrompt(prompt, imagePlugin.settings);
            logger.log("Image generated successfully.");
            return imageUrl;
        } catch (error) {
            logger.error("Failed to generate image:", error);
            alert(`Image generation failed. Details: ${error instanceof Error ? error.message : String(error)}`);
            return null;
        }
    }, [appData.plugins]);

    const handleUiSettingsUpdate = useCallback(async (newSettings: UISettings) => {
        if (!selectedChatId) return;

        const updatedSessions = appData.chatSessions.map(session => 
            session.id === selectedChatId 
                ? { ...session, uiSettings: newSettings } 
                : session
        );
        const updatedData = { ...appData, chatSessions: updatedSessions };
        setAppData(updatedData);
        await persistData(updatedData);
        logger.log("UI appearance settings updated for chat:", selectedChatId);
    }, [appData, persistData, selectedChatId]);

    // Vault Coordination
    const handleOpenVaultSelection = (callback: (ids: string[]) => void) => {
        setVaultSelectionCallback(() => callback);
        setVaultMode('select');
        setIsVaultVisible(true);
    };

    const handleVaultSelectionConfirm = (ids: string[]) => {
        if (vaultSelectionCallback) {
            vaultSelectionCallback(ids);
        }
        setIsVaultVisible(false);
        setVaultSelectionCallback(null);
        setVaultMode('manage'); // Reset
    };

    const handleVaultClose = () => {
        setIsVaultVisible(false);
        setVaultSelectionCallback(null);
        setVaultMode('manage'); // Reset
    };

    const selectedChat = appData.chatSessions.find(s => s.id === selectedChatId);

    const renderMainContent = () => {
        switch (activeView) {
            case 'character-form':
                return <CharacterForm 
                    character={editingCharacter} 
                    onSave={handleSaveCharacter} 
                    onCancel={() => setActiveView('chat')}
                    onDeleteRagSource={handleDeleteRagSource}
                    onGenerateImage={handleGenerateImage}
                    onOpenVaultSelection={handleOpenVaultSelection}
                />;
            case 'plugins':
                return <PluginManager
                    plugins={appData.plugins || []}
                    onPluginsUpdate={handlePluginsUpdate}
                    onSetConfirmation={setConfirmationRequest}
                />;
            case 'lorebooks':
                return <LorebookManager
                    lorebooks={appData.lorebooks || []}
                    onLorebooksUpdate={handleLorebooksUpdate}
                    onSetConfirmation={setConfirmationRequest}
                />;
            case 'chat':
            default:
                return selectedChat ? (
                    <ChatInterface
                        key={selectedChat.id}
                        session={selectedChat}
                        allCharacters={appData.characters}
                        allChatSessions={appData.chatSessions}
                        allLorebooks={appData.lorebooks || []}
                        userKeys={appData.userKeys}
                        onSessionUpdate={handleSessionUpdate}
                        onTriggerHook={triggerPluginHook}
                        onCharacterUpdate={handleCharacterUpdate}
                        onMemoryImport={handleMemoryImport}
                        onSaveBackup={handleSaveBackup}
                        handlePluginApiRequest={handlePluginApiRequest}
                    />
                ) : (
                    <div className="flex-1 flex items-center justify-center h-full bg-background-secondary">
                        <div className="text-center text-text-secondary">
                            <h2 className="text-2xl">Welcome to AI Nexus</h2>
                            <p>Select a chat or create a new one to begin.</p>
                        </div>
                    </div>
                );
        }
    };

    const renderPanelContent = () => {
        switch (activePanel) {
            case 'chats':
                return (
                    <>
                        <div className="flex justify-between items-center mb-2">
                            <h2 className="text-lg font-semibold text-text-primary">Chats</h2>
                            <button onClick={() => setIsChatModalVisible(true)} className="p-2 rounded-md text-text-secondary hover:bg-background-tertiary hover:text-text-primary transition-colors" title="New Chat">
                                <PlusIcon className="w-5 h-5" />
                            </button>
                        </div>
                        <ChatList 
                            chatSessions={appData.chatSessions.filter(c => !!c.isArchived === showArchivedChats)}
                            characters={appData.characters}
                            selectedChatId={selectedChatId}
                            onSelectChat={handleSelectChat}
                            onDeleteChat={handleArchiveChat}
                            onExportChat={handleExportChat}
                            showArchived={showArchivedChats}
                            onToggleArchiveView={() => setShowArchivedChats(!showArchivedChats)}
                            onRestoreChat={handleRestoreChat}
                            onPermanentlyDeleteChat={handlePermanentlyDeleteChat}
                        />
                    </>
                );
            case 'characters':
                return (
                     <CharacterList 
                        characters={appData.characters.filter(c => !!c.isArchived === showArchivedCharacters)}
                        onDeleteCharacter={handleArchiveCharacter}
                        onEditCharacter={handleEditCharacter}
                        onAddNew={handleAddNewCharacter}
                        onExportCharacter={handleExportCharacter}
                        showArchived={showArchivedCharacters}
                        onToggleArchiveView={() => setShowArchivedCharacters(!showArchivedCharacters)}
                        onRestoreCharacter={handleRestoreCharacter}
                        onPermanentlyDeleteCharacter={handlePermanentlyDeleteCharacter}
                    />
                );
            case 'lorebooks':
                return <LorebookManager 
                            lorebooks={appData.lorebooks || []}
                            onLorebooksUpdate={handleLorebooksUpdate}
                            onSetConfirmation={setConfirmationRequest}
                        />;
            case 'none':
                return null;
        }
    };


    return (
        <div 
            className="relative h-screen w-screen overflow-hidden bg-background-primary text-text-primary font-sans flex transition-all duration-500"
            style={selectedChat?.uiSettings?.backgroundImage ? {
                backgroundImage: `url('${selectedChat.uiSettings.backgroundImage}')`,
                backgroundSize: 'cover',
                backgroundPosition: 'center',
                backgroundRepeat: 'no-repeat',
            } : {}}
        >
            <div className="absolute inset-0 bg-background-primary/80 backdrop-blur-sm"></div>
            {isLogViewerVisible && <LogViewer onClose={() => setIsLogViewerVisible(false)} />}
            {isHelpVisible && <HelpModal onClose={() => setIsHelpVisible(false)} />}
            {isChatModalVisible && <ChatSelectionModal characters={appData.characters.filter(c => !c.isArchived)} lorebooks={appData.lorebooks || []} onClose={() => setIsChatModalVisible(false)} onCreateChat={handleCreateChat}/>}
            {isAppearanceModalVisible && (
                <AppearanceModal 
                    settings={selectedChat?.uiSettings || {}}
                    currentChat={selectedChat}
                    allCharacters={appData.characters}
                    onUpdate={handleUiSettingsUpdate}
                    onGenerateImage={handleGenerateImage}
                    onClose={() => setIsAppearanceModalVisible(false)}
                />
            )}
            {isVaultVisible && (
                <Vault 
                    onClose={handleVaultClose} 
                    mode={vaultMode}
                    onConfirmSelection={handleVaultSelectionConfirm}
                />
            )}
            {confirmationRequest && (
                <ConfirmationModal 
                    message={confirmationRequest.message}
                    onConfirm={confirmationRequest.onConfirm}
                    onCancel={confirmationRequest.onCancel}
                />
            )}

            <div className="relative flex-shrink-0 bg-background-secondary/80 w-16 flex flex-col items-center justify-between py-4 border-r border-border-neutral z-20">
                <div className="flex flex-col items-center space-y-2">
                    <button onClick={() => { handlePanelToggle('chats'); setActiveView('chat'); }} title="Chats" className={`p-2 rounded-lg ${activePanel === 'chats' ? 'bg-primary-600 text-text-accent' : 'text-text-secondary hover:bg-background-tertiary'}`}>
                        <ChatBubbleIcon className="w-6 h-6" />
                    </button>
                    <button onClick={() => { handlePanelToggle('characters'); }} title="Characters" className={`p-2 rounded-lg ${activePanel === 'characters' ? 'bg-primary-600 text-text-accent' : 'text-text-secondary hover:bg-background-tertiary'}`}>
                        <UsersIcon className="w-6 h-6" />
                    </button>
                    <button onClick={() => { handlePanelToggle('lorebooks'); }} title="Lorebooks" className={`p-2 rounded-lg ${activePanel === 'lorebooks' ? 'bg-primary-600 text-text-accent' : 'text-text-secondary hover:bg-background-tertiary'}`}>
                        <GlobeIcon className="w-6 h-6" />
                    </button>
                     <button onClick={() => { setActiveView('plugins'); setActivePanel('none'); }} title="Plugins" className={`p-2 rounded-lg ${activeView === 'plugins' ? 'bg-primary-600 text-text-accent' : 'text-text-secondary hover:bg-background-tertiary'}`}>
                        <CodeIcon className="w-6 h-6" />
                    </button>

                    <div className="w-8 border-t border-border-neutral my-2"></div>

                    <button onClick={() => { setIsVaultVisible(true); setVaultMode('manage'); }} title="Secure Vault" className="p-2 rounded-lg text-text-secondary hover:bg-background-tertiary">
                        <VaultIcon className="w-6 h-6" />
                    </button>
                    <button onClick={() => setIsAppearanceModalVisible(true)} title="Appearance Settings" className="p-2 rounded-lg text-text-secondary hover:bg-background-tertiary">
                        <PaletteIcon className="w-6 h-6" />
                    </button>
                    <input type="file" ref={fileInputRef} onChange={handleImportData} accept=".json" className="hidden" />
                    <button onClick={handleSaveBackup} title="Save Full Backup" className="p-2 rounded-lg text-text-secondary hover:bg-background-tertiary">
                        <DownloadIcon className="w-6 h-6" />
                    </button>
                    <button onClick={() => fileInputRef.current?.click()} title="Import Data" className="p-2 rounded-lg text-text-secondary hover:bg-background-tertiary">
                        <UploadIcon className="w-6 h-6" />
                    </button>
                    <button onClick={() => setIsLogViewerVisible(true)} title="View Logs" className="p-2 rounded-lg text-text-secondary hover:bg-background-tertiary">
                        <TerminalIcon className="w-6 h-6" />
                    </button>
                    <button onClick={() => setIsHelpVisible(true)} title="Help" className="p-2 rounded-lg text-text-secondary hover:bg-background-tertiary">
                        <HelpIcon className="w-6 h-6" />
                    </button>

                </div>
                <div className="flex flex-col items-center">
                    <ThemeSwitcher />
                </div>
            </div>

            <aside className={`relative flex-shrink-0 transform transition-all duration-300 ease-in-out bg-background-secondary/80 border-r border-border-neutral flex flex-col overflow-hidden ${activePanel !== 'none' ? 'w-80 p-4' : 'w-0 p-0 border-r-0'}`}>
                {renderPanelContent()}
            </aside>

            <main className="relative flex-1 flex flex-col h-full overflow-hidden">
                {selectedChat?.uiSettings?.bannerImage && (
                    <div className="w-full h-32 md:h-48 flex-shrink-0 bg-black/20">
                        <img src={selectedChat.uiSettings.bannerImage} className="w-full h-full object-cover" alt="Banner"/>
                    </div>
                )}
                <div className="flex-1 min-h-0">
                    {renderMainContent()}
                </div>
            </main>
        </div>
    );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Character, ChatSession, Message, CryptoKeys, GeminiApiRequest, Lorebook } from '../types.ts';
import { streamChatResponse, streamGenericResponse, generateContent } from '../services/geminiService.ts';
import * as cryptoService from '../services/cryptoService.ts';
import * as ttsService from '../services/ttsService.ts';
import * as ragService from '../services/ragService.ts';
import * as lorebookService from '../services/lorebookService.ts';
import * as secureStorage from '../services/secureStorage.ts';
import { logger } from '../services/loggingService.ts';
import { ChatBubbleIcon } from './icons/ChatBubbleIcon.tsx';
import { ImageIcon } from './icons/ImageIcon.tsx';
import { BookIcon } from './icons/BookIcon.tsx';
import { BrainIcon } from './icons/BrainIcon.tsx';
import { SpeakerIcon } from './icons/SpeakerIcon.tsx';
import { MemoryImportModal } from './MemoryImportModal.tsx';
import { CheckCircleIcon } from './icons/CheckCircleIcon.tsx';
import { ExclamationTriangleIcon } from './icons/ExclamationTriangleIcon.tsx';
import { PluginSandbox } from '../services/pluginSandbox.ts';
import { ImageGenerationWindow } from './ImageGenerationWindow.tsx';
import { PaletteIcon } from './icons/PaletteIcon.tsx';
import { InputModal } from './InputModal.tsx';

interface ChatInterfaceProps {
  session: ChatSession;
  allCharacters: Character[];
  allChatSessions: ChatSession[];
  allLorebooks: Lorebook[];
  userKeys?: CryptoKeys;
  onSessionUpdate: (session: ChatSession) => void;
  onCharacterUpdate: (character: Character) => void;
  onTriggerHook: <T, R>(hookName: string, data: T) => Promise<R>;
  onMemoryImport: (fromSessionId: string, toSessionId: string) => void;
  onSaveBackup: () => void;
  handlePluginApiRequest: (request: GeminiApiRequest) => Promise<any>;
}

interface InputModalState {
    title: string;
    label: string;
    placeholder?: string;
    onConfirm: (value: string) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    session, 
    allCharacters, 
    allChatSessions,
    allLorebooks,
    userKeys, 
    onSessionUpdate, 
    onCharacterUpdate, 
    onTriggerHook,
    onMemoryImport,
    onSaveBackup,
    handlePluginApiRequest,
}) => {
  const [currentSession, setCurrentSession] = useState<ChatSession>(session);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [autoConverseStatus, setAutoConverseStatus] = useState<'stopped' | 'running' | 'paused'>('stopped');
  const [isMemoryModalVisible, setIsMemoryModalVisible] = useState(false);
  const [isTtsEnabled, setIsTtsEnabled] = useState(false);
  const [verifiedSignatures, setVerifiedSignatures] = useState<Record<string, boolean>>({});
  const [isImageWindowVisible, setIsImageWindowVisible] = useState(false);
  const [inputModal, setInputModal] = useState<InputModalState | null>(null);

  const nextSpeakerIndex = useRef(0);
  const systemOverride = useRef<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const imageClickTimeout = useRef<number | null>(null);
  const narratorClickTimeout = useRef<number | null>(null);
  const autoConverseTimeout = useRef<number | null>(null);

  // Refs to avoid closure issues with state in timeouts/async calls
  const autoConverseStatusRef = useRef(autoConverseStatus);
  useEffect(() => {
    autoConverseStatusRef.current = autoConverseStatus;
  }, [autoConverseStatus]);

  const currentSessionRef = useRef(session);
  useEffect(() => {
    currentSessionRef.current = currentSession;
  }, [currentSession]);

  const participants = useMemo(() => {
    return allCharacters.filter(c => currentSession.characterIds.includes(c.id));
  }, [allCharacters, currentSession.characterIds]);

  const attachedLorebooks = useMemo(() => {
    return (currentSession.lorebookIds || []).map(id => allLorebooks.find(lb => lb.id === id)).filter(Boolean) as Lorebook[];
  }, [allLorebooks, currentSession.lorebookIds]);

  const avatarSizeClass = useMemo(() => {
    switch (currentSession.uiSettings?.avatarSize) {
      case 'small': return 'w-8 h-8';
      case 'large': return 'w-12 h-12';
      default: return 'w-10 h-10'; // Medium is default
    }
  }, [currentSession.uiSettings?.avatarSize]);

  useEffect(() => {
    if (session.id !== currentSessionRef.current.id) {
        setCurrentSession(session);
        if (autoConverseStatusRef.current !== 'stopped') {
            setAutoConverseStatus('stopped');
            if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
        }
    }
  }, [session]);

  useEffect(() => {
    const verifyAllMessages = async () => {
        const verificationResults: Record<string, boolean> = {};
        for (const msg of currentSession.messages) {
            if (msg.signature && msg.publicKeyJwk) {
                try {
                    const publicKey = await cryptoService.importKey(msg.publicKeyJwk, 'verify');
                    const dataToVerify: Partial<Message> = { ...msg };
                    delete dataToVerify.signature;
                    delete dataToVerify.publicKeyJwk;
                    const canonicalString = cryptoService.createCanonicalString(dataToVerify);
                    verificationResults[msg.timestamp] = await cryptoService.verify(canonicalString, msg.signature, publicKey);
                } catch (e) {
                    logger.error("Message verification failed during check", e);
                    verificationResults[msg.timestamp] = false;
                }
            }
        }
        setVerifiedSignatures(verificationResults);
    };
    verifyAllMessages();
  }, [currentSession.messages]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentSession.messages, isStreaming]);

  useEffect(() => {
    return () => {
      if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
      ttsService.cancel();
    }
  }, []);

  const updateSession = useCallback((updater: (session: ChatSession) => ChatSession) => {
    const newSession = updater(currentSessionRef.current);
    setCurrentSession(newSession);
    onSessionUpdate(newSession);
  }, [onSessionUpdate]);

  const addMessage = useCallback((message: Message) => {
    updateSession(prevSession => ({ ...prevSession, messages: [...prevSession.messages, message] }));
  }, [updateSession]);

  const addSystemMessage = useCallback((content: string) => {
    const systemMessage: Message = {
      role: 'narrator',
      content,
      timestamp: new Date().toISOString()
    };
    addMessage(systemMessage);
  }, [addMessage]);

  const triggerAIResponse = useCallback(async (character: Character, history: Message[], override?: string) => {
    if (history.filter(m => m.content).length === 0) {
      addSystemMessage("AI cannot respond to an empty history.");
      return;
    }

    let finalHistory = history;
    let finalOverride = override || '';

    // --- Lorebook Context Injection ---
    if (attachedLorebooks.length > 0) {
        const loreContext = lorebookService.findRelevantLore(history, attachedLorebooks);
        if (loreContext) {
            logger.log("Injecting Lorebook context for response.", { character: character.name });
            const contextInstruction = `[WORLD INFO]:\n${loreContext}`;
            finalOverride = finalOverride ? `${contextInstruction}\n\n${finalOverride}` : contextInstruction;
        }
    }

    // --- Vault Content Injection ---
    if (character.vaultAttachmentIds && character.vaultAttachmentIds.length > 0) {
        try {
            logger.log(`Fetching ${character.vaultAttachmentIds.length} vault items for character context...`);
            const vaultItems = await secureStorage.getVaultItemsByIds(character.vaultAttachmentIds);
            const vaultContext = vaultItems.map(item => {
                // Heuristic: truncate extremely long text files to prevent context overflow errors
                const content = item.content && item.content.length > 5000 
                    ? item.content.substring(0, 5000) + "... [truncated]" 
                    : item.content || '[Empty]';
                return `File Name: ${item.name}\nContent:\n${content}`;
            }).join('\n\n');

            if (vaultContext) {
                const vaultInstruction = `[ATTACHED VAULT FILES]:\nYou have access to the following files:\n${vaultContext}`;
                finalOverride = finalOverride ? `${vaultInstruction}\n\n${finalOverride}` : vaultInstruction;
            }
        } catch (error) {
            logger.error("Failed to inject vault items into context", error);
        }
    }

    if (character.pluginEnabled && character.pluginCode) {
        addSystemMessage(`Executing character logic for ${character.name}...`);
        try {
            const sandbox = new PluginSandbox(handlePluginApiRequest);
            await sandbox.loadCode(character.pluginCode);

            const hookPayload = { history, systemOverride: finalOverride };
            const modifiedPayload = await sandbox.executeHook<{history: Message[], systemOverride?: string}>('beforeResponseGenerate', hookPayload);

            finalHistory = modifiedPayload.history;
            finalOverride = modifiedPayload.systemOverride || '';

            sandbox.terminate();
            logger.log(`Character logic for "${character.name}" executed successfully.`);
        } catch (error) {
            logger.error(`Error executing character logic for "${character.name}":`, error);
            addSystemMessage(`Error in character logic for ${character.name}. See logs for details.`);
        }
    }


    setIsStreaming(true);
    const modelPlaceholder: Message = {
        role: 'model',
        content: '',
        timestamp: new Date().toISOString(),
        characterId: character.id
    };

    updateSession(current => ({ ...current, messages: [...finalHistory, modelPlaceholder] }));

    let fullResponse = '';

    try {
        await streamChatResponse(
            character,
            participants,
            finalHistory,
            (chunk) => {
                fullResponse += chunk;
                const messages = currentSessionRef.current.messages;
                const lastMessage = messages[messages.length - 1];
                if(lastMessage && lastMessage.timestamp === modelPlaceholder.timestamp) {
                    lastMessage.content = fullResponse;
                    const msgElement = document.getElementById(modelPlaceholder.timestamp);
                    if (msgElement) {
                       msgElement.innerHTML = fullResponse.replace(/\n/g, '<br>');
                    }
                }
            },
            finalOverride
        );
    } catch (error) {
        logger.error("Streaming failed:", error);
        fullResponse = "Sorry, an error occurred while responding.";
    } finally {
        setIsStreaming(false);

        // --- Process Dynamic Avatar Changes ---
        const avatarRegex = /\[change_avatar:\s*(.*?)\]/g;
        let avatarMatch;
        while ((avatarMatch = avatarRegex.exec(fullResponse)) !== null) {
            const description = avatarMatch[1];
            if (description) {
                logger.log(`Character ${character.name} requested avatar change: ${description}`);
                // Async avatar generation
                handleImageGeneration(description, 'direct').then((result: any) => {
                     // We need to fetch the image result properly. handleImageGeneration currently adds a message.
                     // We need a silent generation here.
                     // Re-using the prompt logic:
                     const payload = { type: 'direct', value: description };
                     onTriggerHook('generateImage', payload).then((res: any) => {
                         if (res.url) {
                             logger.log(`Updating avatar for ${character.name}`);
                             onCharacterUpdate({ ...character, avatarUrl: res.url });
                         }
                     });
                });
            }
        }

        // --- Process Inline Image Generation ---
        const imageRegex = /\[generate_image:\s*(.*?)\]/g;
        const imageMatches = [...fullResponse.matchAll(imageRegex)];

        // Clean the response content for display/storage
        let cleanedResponse = fullResponse.replace(avatarRegex, '').replace(imageRegex, '').trim();

        if (cleanedResponse.length > 0 || imageMatches.length > 0) {
            let finalMessage: Message = { ...modelPlaceholder, content: cleanedResponse };

            if (character.keys) {
                try {
                    const privateKey = await cryptoService.importKey(character.keys.privateKey, 'sign');
                    finalMessage.publicKeyJwk = character.keys.publicKey;
                    const dataToSign: Partial<Message> = { ...finalMessage };
                    delete dataToSign.signature;
                    delete dataToSign.publicKeyJwk;
                    const canonicalString = cryptoService.createCanonicalString(dataToSign);
                    finalMessage.signature = await cryptoService.sign(canonicalString, privateKey);
                } catch (e) {
                    logger.error(`Failed to sign message for character ${character.name}`, e);
                }
            }

            if (isTtsEnabled && cleanedResponse) {
                ttsService.speak(cleanedResponse, character.voiceURI);
            }

            updateSession(current => {
                const updatedMessages = current.messages.map(msg =>
                    msg.timestamp === modelPlaceholder.timestamp ? finalMessage : msg
                );
                return { ...current, messages: updatedMessages };
            });

            for (const match of imageMatches) {
                const prompt = match[1];
                if (prompt) {
                    handleImageGeneration(prompt, 'direct');
                }
            }
        } else {
            updateSession(current => ({
                ...current,
                messages: current.messages.filter(m => m.timestamp !== modelPlaceholder.timestamp)
            }));
        }
    }
  }, [participants, isTtsEnabled, updateSession, addSystemMessage, handlePluginApiRequest, attachedLorebooks, onCharacterUpdate, onTriggerHook]);

  const continueAutoConversation = useCallback(async () => {
    if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
    if (autoConverseStatusRef.current !== 'running' || participants.length < 2) {
        if (autoConverseStatusRef.current !== 'paused') {
            setAutoConverseStatus('stopped');
        }
        return;
    }

    const speaker = participants[nextSpeakerIndex.current % participants.length];
    nextSpeakerIndex.current += 1;
    const otherParticipantNames = participants.filter(p => p.id !== speaker.id).map(p => p.name).join(', ');
    const override = `You are in an automated conversation with ${otherParticipantNames}. Continue the conversation naturally based on the history. Your response should be directed at them, not a user. Do not act as a narrator.`;

    await triggerAIResponse(speaker, currentSessionRef.current.messages, override);

    if (autoConverseStatusRef.current === 'running') {
        autoConverseTimeout.current = window.setTimeout(() => continueAutoConversation(), 3000);
    }
  }, [participants, triggerAIResponse]);

  const startAutoConversation = useCallback(async (topic: string) => {
    const starterMessage: Message = {
        role: 'narrator',
        content: `[The AIs will now converse about: "${topic}"]`,
        timestamp: new Date().toISOString()
    };
    const updatedMessages = [...currentSessionRef.current.messages, starterMessage];
    updateSession(current => ({...current, messages: updatedMessages}));

    const firstSpeaker = participants[nextSpeakerIndex.current % participants.length];
    nextSpeakerIndex.current += 1;
    const otherParticipantNames = participants.filter(p => p.id !== firstSpeaker.id).map(p => p.name).join(', ');
    const override = `You are in an automated conversation with ${otherParticipantNames}. The user has set the topic: "${topic}". Start the conversation. Your response should be directed at them, not a user. Do not act as a narrator.`;

    await triggerAIResponse(firstSpeaker, updatedMessages, override);

    if (autoConverseStatusRef.current === 'running') {
        autoConverseTimeout.current = window.setTimeout(continueAutoConversation, 3000);
    }
  }, [participants, triggerAIResponse, updateSession, continueAutoConversation]);

  const handleCommand = async (command: string, args: string) => {
    setInput('');
    switch (command) {
        case 'image': {
            handleImageGeneration(args, 'direct');
            break;
        }
        case 'narrate': {
            handleNarration(args, 'direct');
            break;
        }
        case 'snapshot':
        case 'memorize': {
            const history = currentSessionRef.current.messages.slice(-10);
            if (history.length === 0) {
                addSystemMessage("Not enough conversation history to save a memory snapshot.");
                return;
            }
            addSystemMessage("Generating memory snapshot...");
            const context = history.map(m => `${m.role === 'model' ? allCharacters.find(c => c.id === m.characterId)?.name || 'AI' : 'User'}: ${m.content}`).join('\n');
            const prompt = `Summarize the key events, information, and character developments from this recent conversation snippet into a concise paragraph for a character's long-term memory. Focus on facts and relationship changes. Conversation:\n\n${context}`;

            try {
                // Find a character with a summary config, or default to general generation
                const summaryChar = participants.find(p => p.summaryApiConfig) || participants[0];
                const summaryConfig = summaryChar?.summaryApiConfig || { service: 'default' };

                const summary = await generateContent(prompt, summaryConfig);

                participants.forEach(p => {
                    const updatedMemory = `${p.memory || ''}\n\n[Memory from ${new Date().toLocaleString()}]\n${summary}`;
                    onCharacterUpdate({...p, memory: updatedMemory.trim()});
                });
                addSystemMessage("Memory snapshot saved for all participants using the configured memory manager.");
            } catch (e) {
                logger.error("Failed to generate memory summary", e);
                addSystemMessage("Failed to generate memory summary. See logs for details.");
            }
            break;
        }
        case 'save': {
            addSystemMessage("Saving a full application backup... Your download will begin shortly.");
            onSaveBackup();
            break;
        }
        case 'sys': {
            systemOverride.current = args;
            addSystemMessage(`System override set for next AI response: "${args}"`);
            break;
        }
        case 'character': {
            const [charName, ...promptParts] = args.split(' ');
            const prompt = promptParts.join(' ');
            if (!charName || !prompt) {
                addSystemMessage("Usage: /character <name> <prompt>");
                return;
            }
            const target = participants.find(p => p.name.toLowerCase().startsWith(charName.toLowerCase()));
            if (!target) {
                addSystemMessage(`Character "${charName}" not found in this chat.`);
                return;
            }

            const targetIndex = participants.findIndex(p => p.id === target.id);
            nextSpeakerIndex.current = targetIndex;

            const userMessage = await createUserMessage(prompt);
            const newHistory = [...currentSessionRef.current.messages, userMessage];
            addMessage(userMessage);

            await triggerAIResponse(target, newHistory);
            break;
        }
        case 'converse': {
            if (autoConverseStatusRef.current !== 'stopped') {
                addSystemMessage("A conversation is already in progress. Use /end to stop it, or /pause to pause.");
                return;
            }
            if (participants.length > 1) {
                const topic = args || 'Anything at all.';
                setAutoConverseStatus('running');
                startAutoConversation(topic);
            } else {
                addSystemMessage("You need at least two characters in the chat to start a conversation.");
            }
            break;
        }
        case 'pause': {
            if (autoConverseStatusRef.current === 'running') {
                if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
                setAutoConverseStatus('paused');
                addSystemMessage("AI conversation paused. Use /resume to continue.");
            } else if (autoConverseStatusRef.current === 'paused') {
                addSystemMessage("Conversation is already paused.");
            } else {
                 addSystemMessage("No conversation is running to pause.");
            }
            break;
        }
        case 'resume': {
             if (autoConverseStatusRef.current === 'paused') {
                setAutoConverseStatus('running');
                addSystemMessage("AI conversation resumed.");
                continueAutoConversation();
            } else if (autoConverseStatusRef.current === 'running') {
                addSystemMessage("Conversation is already running.");
            } else {
                addSystemMessage("No paused conversation to resume.");
            }
            break;
        }
        case 'quit':
        case 'end': {
            if (autoConverseStatusRef.current !== 'stopped') {
                if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
                setAutoConverseStatus('stopped');
                addSystemMessage("AI conversation ended by user.");
            } else {
                addSystemMessage("No conversation is running to end.");
            }
            break;
        }
        default:
            addSystemMessage(`Unknown command: /${command}`);
    }
  };

  const createUserMessage = async (content: string): Promise<Message> => {
    let userMessage: Message = { role: 'user', content, timestamp: new Date().toISOString() };
    if (userKeys) {
        try {
            const privateKey = await cryptoService.importKey(userKeys.privateKey, 'sign');
            userMessage.publicKeyJwk = userKeys.publicKey;
            const dataToSign: Partial<Message> = { ...userMessage };
            delete dataToSign.signature;
            delete dataToSign.publicKeyJwk;
            const canonicalString = cryptoService.createCanonicalString(dataToSign);
            userMessage.signature = await cryptoService.sign(canonicalString, privateKey);
        } catch(e) {
            logger.error("Failed to sign user message", e);
        }
    }
    return userMessage;
  };

  const handleSendMessage = useCallback(async () => {
    const trimmedInput = input.trim();
    if (!trimmedInput) return;

    if (isStreaming && autoConverseStatusRef.current === 'stopped') return;

    if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
    if (autoConverseStatusRef.current !== 'stopped') {
        setAutoConverseStatus('stopped');
        addSystemMessage("AI conversation stopped by user message.");
    }

    if (trimmedInput.startsWith('/')) {
        const [command, ...argsParts] = trimmedInput.substring(1).split(' ');
        const args = argsParts.join(' ');
        handleCommand(command.toLowerCase(), args);
        return;
    }

    const userMessage = await createUserMessage(trimmedInput);
    const newHistory = [...currentSessionRef.current.messages, userMessage];
    addMessage(userMessage);
    setInput('');

    if (participants.length > 0) {
        const respondent = participants[nextSpeakerIndex.current % participants.length];
        nextSpeakerIndex.current += 1;

        let finalSystemOverride = systemOverride.current;
        if (respondent.ragEnabled) {
            try {
                const ragContext = await ragService.findRelevantContext(trimmedInput, respondent);
                if (ragContext) {
                    logger.log("Injecting RAG context for response.", { character: respondent.name });
                    const contextInstruction = `[ADDITIONAL CONTEXT FROM KNOWLEDGE BASE]:\n${ragContext}`;
                    finalSystemOverride = finalSystemOverride
                        ? `${contextInstruction}\n\n${finalSystemOverride}`
                        : contextInstruction;
                }
            } catch (e) {
                logger.error("RAG context retrieval failed:", e);
                addSystemMessage(`Could not retrieve context for ${respondent.name}. Check embedding API settings.`);
            }
        }

        await triggerAIResponse(respondent, newHistory, finalSystemOverride || undefined);

        if (systemOverride.current) {
            systemOverride.current = null;
        }
    }

  }, [input, isStreaming, participants, addMessage, addSystemMessage, triggerAIResponse, userKeys, handleCommand]);

  const handleImageGeneration = async (prompt: string, type: 'direct' | 'summary') => {
      const attachmentMessage: Message = {
          role: 'narrator',
          content: `Generating image for prompt: "${type === 'summary' ? 'Summarizing context...' : prompt}"`,
          timestamp: new Date().toISOString(),
          attachment: { type: 'image', status: 'loading', prompt }
      };
      addMessage(attachmentMessage);

      try {
        const payload = type === 'summary'
            ? { type: 'summary', value: prompt }
            : { type: 'direct', value: prompt };

        // Use type assertion instead of explicit generic arguments to avoid parser issues
        const result = await onTriggerHook('generateImage', payload) as {url?: string, error?: string};

        if (result.url) {
            updateSession(curr => {
                const updatedMessages = curr.messages.map((m): Message => m.timestamp === attachmentMessage.timestamp 
                    ? { ...m, content: '', attachment: { ...m.attachment!, status: 'done', url: result.url } }
                    : m
                );
                return { ...curr, messages: updatedMessages };
            });
            return result; // Return result for potential chaining
        } else {
            throw new Error(result.error || 'Image generation failed with no message.');
        }
      } catch (error) {
           const errorMessage = error instanceof Error ? error.message : String(error);
           logger.error('Image generation failed:', error);
           updateSession(curr => {
                const updatedMessages = curr.messages.map((m): Message => m.timestamp === attachmentMessage.timestamp 
                    ? { ...m, content: `Image generation failed: ${errorMessage}`, attachment: { ...m.attachment!, status: 'error' } }
                    : m
                );
                return { ...curr, messages: updatedMessages };
            });
      }
  };

  const handleGenerateImageInWindow = useCallback(async (prompt: string) => {
    logger.log("Generating image in floating window for prompt:", prompt);
    const payload = { type: 'direct', value: prompt };
    // Use type assertion instead of explicit generic arguments to avoid parser issues
    const result = await onTriggerHook('generateImage', payload) as {url?: string, error?: string};
    return result;
  }, [onTriggerHook]);

  const handleNarration = async (prompt: string, type: 'direct' | 'summary') => {
    let finalPrompt = prompt;
    if (type === 'summary') {
        const summaryPrompt = `Based on the following conversation, create a short, descriptive narration of the current scene or situation. Be creative and concise. Conversation:\n\n${prompt}`;
        try {
            // Use session default config
            finalPrompt = await generateContent(summaryPrompt);
        } catch(e) {
            addSystemMessage("Failed to summarize context for narration.");
            return;
        }
    }

    const narratorPlaceholder: Message = { role: 'narrator', content: '', timestamp: new Date().toISOString() };
    addMessage(narratorPlaceholder);

    let fullResponse = '';
    await streamGenericResponse(
        "You are a neutral, third-person narrator for a story. Describe the scene or events based on the user's request.",
        finalPrompt,
        (chunk) => {
            fullResponse += chunk;
            const msgElement = document.getElementById(narratorPlaceholder.timestamp);
            if (msgElement) {
                msgElement.innerHTML = fullResponse.replace(/\n/g, '<br>');
            }
        }
    );
     updateSession(curr => {
        const finalMessages = curr.messages.map(m => m.timestamp === narratorPlaceholder.timestamp ? {...m, content: fullResponse} : m);
        return { ...curr, messages: finalMessages };
    });
  };

  const handleImageButtonClick = () => {
    if (imageClickTimeout.current) {
      clearTimeout(imageClickTimeout.current);
      imageClickTimeout.current = null;
      const context = currentSessionRef.current.messages.slice(-5).map(m => `${m.role}: ${m.content}`).join('\n');
      handleImageGeneration(context, 'summary');
    } else {
      imageClickTimeout.current = window.setTimeout(() => {
        setInputModal({
            title: "Generate Image",
            label: "Enter a prompt for the image:",
            placeholder: "A cyberpunk city in the rain...",
            onConfirm: (prompt) => {
                handleImageGeneration(prompt, 'direct');
                setInputModal(null);
            }
        });
        imageClickTimeout.current = null;
      }, 250);
    }
  };

  const handleNarratorButtonClick = () => {
    if (narratorClickTimeout.current) {
      clearTimeout(narratorClickTimeout.current);
      narratorClickTimeout.current = null;
      const context = currentSessionRef.current.messages.slice(-5).map(m => `${m.role}: ${m.content}`).join('\n');
      handleNarration(context, 'summary');
    } else {
      narratorClickTimeout.current = window.setTimeout(() => {
        setInputModal({
            title: "Narrator Instruction",
            label: "Enter a narration instruction:",
            placeholder: "Describe the weather changing unexpectedly...",
            onConfirm: (prompt) => {
                handleNarration(prompt, 'direct');
                setInputModal(null);
            }
        });
        narratorClickTimeout.current = null;
      }, 250);
    }
  };

  const renderMessageContent = (message: Message) => {
    if (message.attachment?.type === 'image') {
        switch(message.attachment.status) {
            case 'loading': return <div className="p-4 text-center">Generating image...</div>;
            case 'done': return <img src={message.attachment.url} alt={message.attachment.prompt || 'Generated Image'} className="rounded-lg max-w-sm" />;
            case 'error': return null;
        }
    }
    return <span id={message.timestamp} dangerouslySetInnerHTML={{ __html: message.content.replace(/\n/g, '<br />') }} />;
  };

  const getCharacterById = (id: string) => allCharacters.find(c => c.id === id);

  const isInputDisabled = isStreaming && autoConverseStatus === 'stopped';

  return (
    <div className="flex flex-col h-full bg-background-primary">
      {isImageWindowVisible && (
        <ImageGenerationWindow 
            onGenerate={handleGenerateImageInWindow}
            onClose={() => setIsImageWindowVisible(false)}
        />
      )}
      {isMemoryModalVisible && (
        <MemoryImportModal 
            allSessions={allChatSessions}
            currentSessionId={currentSession.id}
            onClose={() => setIsMemoryModalVisible(false)}
            onImport={(fromSessionId) => {
                onMemoryImport(fromSessionId, currentSession.id);
                setIsMemoryModalVisible(false);
            }}
        />
      )}
      {inputModal && (
        <InputModal 
            title={inputModal.title}
            label={inputModal.label}
            placeholder={inputModal.placeholder}
            onConfirm={inputModal.onConfirm}
            onCancel={() => setInputModal(null)}
        />
      )}
      <header className="flex items-center p-3 border-b border-border-neutral">
        <div className="flex -space-x-4">
            {participants.slice(0, 3).map(p => (
                <img key={p.id} src={p.avatarUrl || `https://picsum.photos/seed/${p.id}/40/40`} alt={p.name} className="w-10 h-10 rounded-full border-2 border-background-primary"/>
            ))}
        </div>
        <div className="ml-4 flex-1 min-w-0">
          <h2 className="text-lg font-bold text-text-primary truncate">{session.name}</h2>
          <p className="text-sm text-text-secondary truncate">{participants.map(p=>p.name).join(', ')}</p>
        </div>
      </header>

      <div className="flex-1 p-4 overflow-y-auto space-y-4">
        {currentSession.messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-text-secondary">
            <ChatBubbleIcon className="w-16 h-16 mb-4" />
            <p>No messages yet. Start the conversation!</p>
          </div>
        ) : (
          currentSession.messages.map((msg, index) => {
            if (msg.role === 'narrator') {
              return (
                <div key={index} className="text-center my-2 group relative">
                  <p id={msg.timestamp} className="text-sm text-text-secondary italic px-4">{renderMessageContent(msg)}</p>
                  <div className="absolute top-1/2 -translate-y-1/2 right-0 flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                     <button onClick={() => ttsService.speak(msg.content)} title="Read Aloud" className="p-1 rounded-full text-text-secondary hover:bg-background-tertiary">
                        <SpeakerIcon className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              );
            }
            const msgCharacter = msg.characterId ? getCharacterById(msg.characterId) : null;
            const isUser = msg.role === 'user';
            const characterVoiceURI = msg.role === 'model' && msgCharacter ? msgCharacter.voiceURI : undefined;
            return (
              <div key={index} className={`flex items-start gap-3 group ${isUser ? 'justify-end' : 'justify-start'}`}>
                {msg.role === 'model' && msgCharacter && (
                  <img src={msgCharacter.avatarUrl || `https://picsum.photos/seed/${msgCharacter.id}/40/40`} alt={msgCharacter.name} className={`${avatarSizeClass} rounded-full flex-shrink-0`} title={msgCharacter.name}/>
                )}
                <div className={`relative max-w-xl p-3 rounded-lg ${
                    isUser
                      ? 'bg-primary-600 text-text-accent'
                      : 'bg-background-secondary text-text-primary'
                  }`}>
                  <div className="absolute top-0 -translate-y-1/2 flex items-center opacity-0 group-hover:opacity-100 transition-opacity" style={isUser ? {left: '-2rem'} : {right: '-2rem'}}>
                     <button onClick={() => ttsService.speak(msg.content, characterVoiceURI)} title="Read Aloud" className="p-1 rounded-full text-text-secondary bg-background-tertiary hover:bg-opacity-80">
                        <SpeakerIcon className="w-4 h-4" />
                    </button>
                  </div>
                  {msg.role === 'model' && msgCharacter && <p className="font-bold text-sm mb-1">{msgCharacter.name}</p>}
                  {renderMessageContent(msg)}
                  {msg.signature && (
                    <div className="absolute -bottom-2 -right-2 bg-background-primary rounded-full p-0.5">
                        {verifiedSignatures[msg.timestamp] === true && <CheckCircleIcon className="w-4 h-4 text-accent-green" title="Signature Verified" />}
                        {verifiedSignatures[msg.timestamp] === false && <ExclamationTriangleIcon className="w-4 h-4 text-accent-yellow" title="Signature Invalid" />}
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 border-t border-border-neutral">
        <div className="flex items-center bg-background-secondary rounded-lg p-2">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); } }}
            placeholder={
                autoConverseStatus === 'running' ? "AI conversation in progress... (/pause or /end)" :
                autoConverseStatus === 'paused' ? "AI conversation paused. (/resume or /end)" :
                `Message ${session.name}... (/converse)`
            }
            className="flex-1 bg-transparent resize-none focus:outline-none px-2 text-text-primary"
            rows={1}
            disabled={isInputDisabled}
          />
          <button 
                onClick={() => setIsImageWindowVisible(!isImageWindowVisible)} 
                title="Open Image Generation Window" 
                className={`p-2 rounded-full transition-colors ${isImageWindowVisible ? 'text-primary-500' : 'text-text-secondary hover:text-primary-500'}`} disabled={isInputDisabled}
            >
                <PaletteIcon className="w-6 h-6" />
            </button>
            <button 
                onClick={() => setIsTtsEnabled(!isTtsEnabled)} 
                title={isTtsEnabled ? "Disable Auto-TTS" : "Enable Auto-TTS for AI Responses"} 
